-- LENGUA 1º ESO (10 textos) — tipos de textos
-- =====================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('lengua', 'eso', '{1}', 'Los textos descriptivos',
'Un texto descriptivo es aquel que explica con palabras cómo es una persona, un animal, un objeto, un lugar o un sentimiento. Su objetivo principal es que el lector pueda imaginar con claridad aquello que se describe, casi como si lo estuviera viendo. Para lograrlo, quien escribe utiliza muchos adjetivos, comparaciones y referencias a los cinco sentidos: la vista, el oído, el tacto, el olfato y el gusto. Existen dos grandes tipos de descripciones. La descripción objetiva busca ser precisa y neutra, sin incluir opiniones personales; es la que usan los científicos, los manuales técnicos o las enciclopedias. La descripción subjetiva, en cambio, refleja los sentimientos y la visión personal de quien escribe, por lo que es propia de la literatura y la poesía. Un buen ejercicio para practicar consiste en describir primero un objeto cotidiano como si lo hiciera un científico y después volver a describirlo mostrando las emociones que despierta. Así se comprueba cómo cambia el mismo contenido según la intención del autor. La descripción suele aparecer combinada con otros tipos de textos, como la narración, ya que ayuda a situar al lector dentro de la historia.',
'[{"pregunta":"¿Cuál es el objetivo principal de un texto descriptivo?","opciones":["Convencer al lector","Que el lector imagine lo descrito","Contar una historia","Dar instrucciones"],"correcta":1},{"pregunta":"¿Qué recurso es característico de la descripción?","opciones":["Los verbos en pasado","Los adjetivos y comparaciones","Los signos matemáticos","Los diálogos"],"correcta":1},{"pregunta":"¿Cuál es la diferencia entre descripción objetiva y subjetiva?","opciones":["La objetiva es más larga","La subjetiva refleja opiniones personales","La objetiva usa diálogos","La subjetiva es científica"],"correcta":1},{"pregunta":"¿Con qué otro tipo de texto suele combinarse la descripción?","opciones":["Con la narración","Con la receta","Con el examen","Con la agenda"],"correcta":0}]'::jsonb),

('lengua', 'eso', '{1}', 'Los textos instructivos',
'Los textos instructivos sirven para explicar cómo hacer algo paso a paso. Los encontramos en las recetas de cocina, en los manuales de montaje de un mueble, en las instrucciones de un videojuego o en las normas de un aula. Su finalidad es que el lector pueda realizar una tarea correctamente, sin olvidarse de ningún detalle. Por eso, el lenguaje de estos textos tiene unas características muy marcadas. Suelen usar verbos en imperativo, como ''mezcla'' o ''pulsa'', o bien en infinitivo, como ''mezclar'' o ''pulsar''. Además, las instrucciones se ordenan numeradas o con viñetas para que quede claro cuál va primero y cuál después. Muchas veces aparecen acompañadas de imágenes o esquemas que refuerzan la información. Un buen texto instructivo debe ser claro, ordenado y breve: si se enreda con adjetivos o descripciones innecesarias, el lector se pierde. También es importante indicar los materiales que se necesitan antes de empezar la actividad. Saber redactar instrucciones resulta útil en la vida diaria, porque permite enseñar a otras personas tareas que nosotros ya dominamos, desde preparar un bocadillo hasta configurar un teléfono móvil.',
'[{"pregunta":"¿Para qué sirve un texto instructivo?","opciones":["Para entretener","Para explicar cómo hacer algo","Para informar de noticias","Para expresar sentimientos"],"correcta":1},{"pregunta":"¿Qué forma verbal es típica de las instrucciones?","opciones":["Subjuntivo","Imperativo o infinitivo","Gerundio","Condicional"],"correcta":1},{"pregunta":"¿Qué deben indicar las instrucciones antes de empezar?","opciones":["El precio","Los materiales necesarios","El autor","La fecha"],"correcta":1},{"pregunta":"¿Cómo debe ser un buen texto instructivo?","opciones":["Largo y literario","Claro, ordenado y breve","Subjetivo y emocional","Poético"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{1}', 'Los textos expositivos',
'Un texto expositivo tiene como finalidad informar sobre un tema de manera clara y ordenada, sin mostrar opiniones personales. Se utiliza mucho en los libros de texto, en los artículos de divulgación científica, en las enciclopedias y en las conferencias. Quien escribe un texto expositivo debe asegurarse de que el lector, aunque no conozca el tema, pueda entenderlo al acabar la lectura. Para ello se emplea un lenguaje objetivo, con datos precisos, ejemplos y definiciones. Los textos expositivos suelen organizarse en tres partes principales. La introducción presenta el tema y explica de qué se va a hablar. El desarrollo expone la información de forma estructurada, a menudo en varios apartados con títulos. La conclusión resume las ideas más importantes. También es habitual incluir gráficos, tablas, fotografías o mapas que ayuden a comprender mejor el contenido. Existen dos variantes: los textos expositivos divulgativos, dirigidos al público general, y los especializados, pensados para expertos en una materia. Los primeros emplean un vocabulario accesible, mientras que los segundos utilizan tecnicismos propios de la disciplina. Leer textos expositivos con atención ayuda a aprender y a ampliar conocimientos de manera autónoma.',
'[{"pregunta":"¿Cuál es la finalidad de un texto expositivo?","opciones":["Convencer","Informar de forma clara","Narrar una aventura","Describir paisajes"],"correcta":1},{"pregunta":"¿Qué partes suele tener un texto expositivo?","opciones":["Principio y fin","Introducción, desarrollo y conclusión","Verso y rima","Diálogo y acotación"],"correcta":1},{"pregunta":"¿Qué diferencia a los textos expositivos divulgativos de los especializados?","opciones":["El número de páginas","El vocabulario","El color","El formato"],"correcta":1},{"pregunta":"¿Qué recurso NO es típico de un texto expositivo?","opciones":["Un gráfico","Una opinión emocional","Una definición","Un dato"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{1}', 'Los textos argumentativos',
'Los textos argumentativos son aquellos en los que el autor defiende una opinión y trata de convencer al lector de que su postura es la correcta. Se utilizan mucho en los debates, en los artículos de opinión de los periódicos, en los anuncios publicitarios y en las cartas al director. La estructura más habitual consta de tres partes. Primero se presenta la tesis, que es la idea principal que se quiere defender. Después vienen los argumentos, que son las razones que apoyan la tesis y pueden basarse en datos, ejemplos, experiencias personales o en la opinión de personas expertas. Finalmente se cierra con una conclusión que refuerza la postura inicial. Un buen argumentador no solo expone sus razones, sino que también intenta prever las posibles objeciones del contrario y responderlas. El lenguaje suele ser cuidado, con conectores como ''en primer lugar'', ''además'', ''por otra parte'' o ''en conclusión''. Es importante distinguir entre los argumentos sólidos, que se apoyan en hechos verificables, y las falacias, que son razonamientos aparentemente válidos pero engañosos. Aprender a construir y a analizar argumentos ayuda a pensar con espíritu crítico y a participar mejor en la vida democrática.',
'[{"pregunta":"¿Qué se quiere conseguir con un texto argumentativo?","opciones":["Entretener","Convencer al lector","Describir un paisaje","Dar instrucciones"],"correcta":1},{"pregunta":"¿Qué es la tesis?","opciones":["Un adjetivo","La idea principal que se defiende","El final del texto","Un ejemplo"],"correcta":1},{"pregunta":"¿Qué son las falacias?","opciones":["Datos verificables","Razonamientos engañosos","Opiniones verdaderas","Conectores"],"correcta":1},{"pregunta":"¿Qué conector es típico de un texto argumentativo?","opciones":["Érase una vez","En primer lugar","De pronto","Colorín colorado"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{1}', 'Los textos dialogados',
'Un texto dialogado es aquel en el que se reproducen las palabras que intercambian dos o más personas. Los diálogos aparecen en muchos tipos de textos distintos: en las novelas, en el teatro, en los guiones de cine, en los cómics y, por supuesto, en las conversaciones reales. En la escritura, los diálogos se marcan de forma especial para que el lector sepa quién habla en cada momento. En español se utiliza la raya larga, que es diferente del guion corto, para indicar la intervención de cada personaje. Cuando el narrador intercala comentarios dentro de lo que dice alguien, también se usan rayas para separar sus palabras. Los diálogos sirven para varias funciones importantes. En una narración, permiten que los personajes se expresen con su propia voz, mostrando su personalidad, sus emociones y su forma de hablar. En el teatro, son la base de toda la obra, porque apenas hay descripciones: todo se conoce a través de lo que dicen los personajes y de las acotaciones. Además, los diálogos hacen los textos más dinámicos y cercanos. Practicar la escritura de diálogos ayuda a construir personajes creíbles y a dar ritmo a las historias.',
'[{"pregunta":"¿Qué se reproduce en un texto dialogado?","opciones":["Un paisaje","Las palabras que intercambian dos o más personas","Un dato científico","Una receta"],"correcta":1},{"pregunta":"¿Qué signo marca la intervención de un personaje en español?","opciones":["El paréntesis","La raya larga","La coma","El punto y coma"],"correcta":1},{"pregunta":"¿Qué función tienen los diálogos en una narración?","opciones":["Mostrar la voz del personaje","Dar datos técnicos","Enumerar materiales","Calcular precios"],"correcta":0},{"pregunta":"¿Dónde NO suelen aparecer diálogos?","opciones":["En el teatro","En los cómics","En las tablas matemáticas","En las novelas"],"correcta":2}]'::jsonb),

('lengua', 'eso', '{1}', 'La carta y el correo electrónico',
'La carta y el correo electrónico son dos tipos de textos que sirven para comunicarse con una persona que no está presente. Aunque uno se escribe a mano o se imprime y el otro se envía por internet, ambos comparten una estructura parecida. En una carta tradicional aparece primero el lugar y la fecha, después el encabezamiento con el saludo al destinatario, luego el cuerpo del mensaje y finalmente la despedida y la firma del remitente. El correo electrónico añade el asunto, que debe resumir en pocas palabras de qué trata el mensaje, y la dirección del destinatario en la parte superior. Existen dos tipos principales: las cartas formales y las informales. Las formales se dirigen a personas con las que no tenemos confianza, como el director de un instituto o una empresa, y utilizan un lenguaje cuidado, con expresiones como ''Estimado señor'' o ''Atentamente''. Las informales se escriben a familiares o amigos y emplean un tono cercano, con saludos como ''Hola, querida abuela''. En el correo electrónico es importante revisar bien el texto antes de enviarlo, porque los errores quedan por escrito. También conviene evitar el uso excesivo de mayúsculas, que en internet equivale a gritar.',
'[{"pregunta":"¿Qué elemento añade el correo electrónico respecto a la carta tradicional?","opciones":["La firma","El asunto","La fecha","El saludo"],"correcta":1},{"pregunta":"¿Qué lenguaje se usa en una carta formal?","opciones":["Muy coloquial","Cuidado y respetuoso","Técnico y matemático","Poético"],"correcta":1},{"pregunta":"¿Qué significa escribir con mayúsculas en internet?","opciones":["Escribir con elegancia","Equivale a gritar","Indica importancia","No significa nada"],"correcta":1},{"pregunta":"¿A quién se dirige una carta informal?","opciones":["Al director de la empresa","A familiares o amigos","A un juez","A un desconocido"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{1}', 'Los textos predictivos',
'Los textos predictivos son aquellos que anuncian lo que podría ocurrir en el futuro a partir de datos del presente. El ejemplo más común es el pronóstico del tiempo, pero también pertenecen a esta categoría los horóscopos, las previsiones económicas, los informes sobre el cambio climático y las predicciones electorales. Su característica principal es que no afirman con seguridad lo que va a pasar, sino que utilizan fórmulas de probabilidad. Por eso abundan los verbos en futuro (''lloverá'', ''subirá''), el condicional (''podría haber nieblas'') y expresiones como ''es posible que'', ''probablemente'' o ''se prevé que''. Un buen texto predictivo se basa en datos fiables y en el estudio de lo que ha pasado en situaciones similares. Los meteorólogos, por ejemplo, analizan los mapas de presión atmosférica, las temperaturas y las corrientes para elaborar sus pronósticos. Sin embargo, conviene recordar que ninguna predicción es completamente segura: siempre existe un margen de error. Por eso, los horóscopos, que no se apoyan en ningún método científico, no deben confundirse con las predicciones científicas, aunque en apariencia utilicen un lenguaje parecido. Saber distinguir una predicción rigurosa de otra que no lo es forma parte del pensamiento crítico.',
'[{"pregunta":"¿Qué anuncian los textos predictivos?","opciones":["El pasado","Lo que podría ocurrir","Una receta","Una opinión"],"correcta":1},{"pregunta":"¿Qué tiempo verbal se usa con frecuencia?","opciones":["Pretérito perfecto","Futuro y condicional","Imperativo","Presente de indicativo"],"correcta":1},{"pregunta":"Según el texto, ¿qué diferencia al horóscopo de un pronóstico meteorológico?","opciones":["El horóscopo no se apoya en ningún método científico","El horóscopo es más fiable","No hay diferencia","El pronóstico no usa datos"],"correcta":0},{"pregunta":"¿Qué expresión es típica de un texto predictivo?","opciones":["Érase una vez","Es probable que","Atentamente","Punto final"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{1}', 'La noticia periodística',
'La noticia es un texto periodístico que informa de un hecho actual de interés general. Para que una noticia esté bien escrita debe responder a seis preguntas básicas, conocidas como las seis W del periodismo: qué, quién, cuándo, dónde, cómo y por qué. Su estructura es muy característica y se compone de tres partes. El titular es la frase breve y llamativa que encabeza la noticia y resume lo más importante. A veces se acompaña de un antetítulo o un subtítulo que aportan más información. La entradilla o lead es el primer párrafo, que responde a las preguntas esenciales y sirve para que el lector con prisa se haga una idea rápida de lo ocurrido. El cuerpo desarrolla los detalles del hecho en orden de mayor a menor importancia. Esta forma de organizar la información se llama pirámide invertida, porque lo esencial va arriba y lo secundario abajo. Así, si el lector deja la noticia a la mitad, ya tiene lo fundamental. El lenguaje de las noticias debe ser claro, objetivo y preciso: no se opina, solo se informa. Las opiniones del periódico aparecen en otros géneros, como el editorial o los artículos de opinión, nunca dentro de una noticia.',
'[{"pregunta":"¿A cuántas preguntas básicas debe responder una noticia?","opciones":["Tres","Seis","Diez","Dos"],"correcta":1},{"pregunta":"¿Qué es la pirámide invertida?","opciones":["Un monumento","Organizar la información de mayor a menor importancia","Un tipo de titular","Un género teatral"],"correcta":1},{"pregunta":"¿Cómo debe ser el lenguaje de una noticia?","opciones":["Opinativo","Objetivo y preciso","Literario","Coloquial"],"correcta":1},{"pregunta":"¿Dónde aparecen las opiniones del periódico?","opciones":["En la noticia","En el editorial","En la entradilla","En el titular"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{1}', 'El cartel publicitario',
'El cartel publicitario es un texto breve que combina imagen y palabras con la intención de convencer al receptor de que compre un producto, contrate un servicio o adopte una actitud. A diferencia de otros textos, su primer impacto es visual: quien pasa por delante solo dispone de unos segundos para captar el mensaje, por lo que todo debe entrar por los ojos. Los elementos principales de un cartel son la imagen, que suele ocupar la mayor parte del espacio, el eslogan, que es una frase corta y fácil de recordar, la marca del producto y, a veces, un pequeño texto explicativo. El eslogan utiliza recursos muy ingeniosos: juegos de palabras, rimas, metáforas y exageraciones. La tipografía (el estilo de las letras) y los colores también forman parte del mensaje y transmiten emociones: el rojo sugiere pasión o urgencia, el verde naturaleza, el azul tranquilidad. La publicidad no siempre informa de manera fiel; muchas veces manipula los deseos del receptor asociando el producto con la felicidad, el éxito o la belleza. Por eso es importante desarrollar una mirada crítica y preguntarse si realmente necesitamos lo que se anuncia o si solo estamos dejándonos llevar por el atractivo del cartel.',
'[{"pregunta":"¿Cuál es el objetivo del cartel publicitario?","opciones":["Narrar una historia","Convencer al receptor","Describir un paisaje","Explicar gramática"],"correcta":1},{"pregunta":"¿Qué es el eslogan?","opciones":["La marca","Una frase corta y fácil de recordar","El precio","El autor"],"correcta":1},{"pregunta":"Según el texto, ¿qué transmite el color azul?","opciones":["Pasión","Tranquilidad","Urgencia","Ira"],"correcta":1},{"pregunta":"¿Por qué conviene mirar la publicidad con espíritu crítico?","opciones":["Porque es muy larga","Porque puede manipular nuestros deseos","Porque usa colores","Porque es gratis"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{1}', 'El cómic como texto',
'El cómic es una forma de narración que combina imágenes y palabras para contar una historia. Nacido a finales del siglo XIX, se ha convertido en uno de los medios más populares del mundo, con tradiciones tan distintas como el cómic americano (superhéroes), el manga japonés o la historieta europea (Tintín, Astérix). Un cómic se organiza en viñetas, que son cada uno de los recuadros dibujados. Dentro de las viñetas, los personajes hablan mediante globos o bocadillos, cuya forma indica el tipo de mensaje: los redondeados son diálogos normales, los dentados representan gritos y los formados por nubes pequeñas son pensamientos. El texto del narrador, cuando existe, aparece en cartuchos rectangulares en la parte superior o inferior. Además, los cómics cuentan con un recurso único: las onomatopeyas, palabras como ''¡bang!'', ''¡crash!'' o ''¡zas!'' que imitan los sonidos de la acción. El dibujo también comunica a través del tamaño de los planos, los gestos de los personajes y los colores. Leer un cómic es una lectura completa, porque el cerebro procesa simultáneamente la imagen y la palabra, lo que desarrolla la imaginación y la comprensión visual. Por eso cada vez más profesores lo usan como recurso educativo.',
'[{"pregunta":"¿Cómo se llama cada recuadro dibujado del cómic?","opciones":["Globo","Viñeta","Cartucho","Página"],"correcta":1},{"pregunta":"¿Qué forma tiene el bocadillo que representa un pensamiento?","opciones":["Dentado","Rectangular","De nubes pequeñas","Triangular"],"correcta":2},{"pregunta":"¿Qué son las onomatopeyas?","opciones":["Dibujos de personajes","Palabras que imitan sonidos","Nombres de autores","Títulos de capítulos"],"correcta":1},{"pregunta":"¿Qué tradición NO se menciona en el texto?","opciones":["Cómic americano","Manga japonés","Historieta europea","Cómic africano"],"correcta":3}]'::jsonb);

-- =====================================================
-- LENGUA 2º ESO (10 textos) — literatura medieval
-- =====================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('lengua', 'eso', '{2}', 'Las jarchas: los primeros versos de la Península',
'Las jarchas son las composiciones líricas más antiguas que se conservan escritas en la Península Ibérica. Se trata de pequeños poemas de dos, tres o cuatro versos escritos en mozárabe, la lengua romance que hablaban los cristianos que vivían en territorio musulmán. Los poetas árabes y hebreos de Al-Ándalus las utilizaban como cierre o estribillo de unas composiciones más largas llamadas moaxajas. Durante siglos, las jarchas permanecieron olvidadas hasta que en 1948 el investigador Samuel Stern descubrió algunas de ellas en manuscritos hebreos, dando un giro enorme a la historia de la literatura española. Su contenido resulta sorprendente por su sencillez y emoción: casi todas están puestas en boca de una muchacha enamorada que se lamenta ante su madre o sus hermanas por la ausencia del amado, al que llama ''habib''. La voz femenina, el tema del amor doloroso y el tono íntimo convierten a las jarchas en el origen de la lírica popular peninsular. Su descubrimiento demostró que ya en el siglo XI existía una rica tradición poética en lengua romance, mucho antes de lo que se pensaba. Hoy se estudian como el primer eslabón de la literatura en español.',
'[{"pregunta":"¿En qué lengua están escritas las jarchas?","opciones":["Árabe","Mozárabe","Latín","Griego"],"correcta":1},{"pregunta":"¿Qué composición más larga cerraba una jarcha?","opciones":["El soneto","La moaxaja","El romance","La oda"],"correcta":1},{"pregunta":"¿Quién suele ser la voz que habla en las jarchas?","opciones":["Un caballero","Una muchacha enamorada","Un rey","Un sacerdote"],"correcta":1},{"pregunta":"¿En qué año se descubrieron?","opciones":["1848","1948","1748","2048"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{2}', 'El Cantar de Mio Cid',
'El Cantar de Mio Cid es la obra épica más importante de la literatura española medieval. Compuesto hacia el año 1200 por un autor anónimo, aunque algunos estudiosos lo atribuyen a Per Abbat, narra las hazañas del caballero castellano Rodrigo Díaz de Vivar, conocido como el Cid Campeador. El poema cuenta cómo, tras ser desterrado injustamente por el rey Alfonso VI, el Cid emprende una campaña militar para recuperar su honor. El Cantar se divide en tres partes o cantares. El primero, ''Cantar del destierro'', muestra la salida de Castilla del protagonista. El segundo, ''Cantar de las bodas'', relata la conquista de Valencia y el matrimonio de sus hijas con los infantes de Carrión. El tercero, ''Cantar de la afrenta de Corpes'', narra cómo esos yernos maltratan a las hijas del Cid en un robledal, y cómo el héroe exige justicia al rey. La obra tiene un tono realista muy distinto de otros cantares europeos, como la Chanson de Roland francesa. El Cid no es un héroe mitológico, sino un hombre de carne y hueso, preocupado por el dinero, la familia y el honor. Está escrito en versos irregulares, con una pausa central llamada cesura, y con rima asonante.',
'[{"pregunta":"¿De qué personaje histórico trata el Cantar?","opciones":["Carlomagno","Rodrigo Díaz de Vivar","Alfonso X","Jaime I"],"correcta":1},{"pregunta":"¿Cuántas partes o cantares tiene la obra?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Qué se narra en el Cantar de la afrenta de Corpes?","opciones":["La boda del Cid","El maltrato a sus hijas por los infantes","La conquista de Toledo","La muerte del rey"],"correcta":1},{"pregunta":"¿Qué tipo de rima tiene el poema?","opciones":["Consonante","Asonante","Libre","Interior"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{2}', 'El mester de clerecía',
'En el siglo XIII apareció en Castilla una nueva forma de hacer poesía llamada mester de clerecía, que significa literalmente ''oficio de clérigos''. Frente al mester de juglaría, oral, popular y con versos irregulares, los clérigos (hombres cultos formados en los monasterios) escribían obras muy distintas: utilizaban una estrofa fija llamada cuaderna vía, compuesta por cuatro versos de catorce sílabas (alejandrinos) con rima consonante AAAA. Este cuidado métrico reflejaba la formación latina de sus autores y la voluntad de demostrar que la lengua romance también podía alcanzar la dignidad del latín. Los temas del mester de clerecía son principalmente religiosos, morales o heroicos, pero tratados con una clara intención didáctica: enseñar al pueblo los valores cristianos. El autor más importante de este movimiento es Gonzalo de Berceo, un monje riojano del monasterio de San Millán de la Cogolla, considerado el primer poeta de nombre conocido en lengua castellana. Escribió los famosos ''Milagros de Nuestra Señora'', una colección de veinticinco relatos en los que la Virgen María salva de distintos peligros a sus devotos. Más tarde, en el siglo XIV, destacarán dos obras maestras: el ''Libro de buen amor'' del Arcipreste de Hita y el ''Libro rimado de palacio'' de Pero López de Ayala.',
'[{"pregunta":"¿Qué significa ''mester de clerecía''?","opciones":["Oficio de reyes","Oficio de clérigos","Oficio de juglares","Oficio de caballeros"],"correcta":1},{"pregunta":"¿Qué estrofa usaba el mester de clerecía?","opciones":["El soneto","La cuaderna vía","El romance","La octava real"],"correcta":1},{"pregunta":"¿Quién es considerado el primer poeta de nombre conocido en castellano?","opciones":["Jorge Manrique","Gonzalo de Berceo","Juan Ruiz","Don Juan Manuel"],"correcta":1},{"pregunta":"¿Cuántos versos tiene la cuaderna vía?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":2}]'::jsonb),

('lengua', 'eso', '{2}', 'El Libro de buen amor',
'El Libro de buen amor, escrito hacia 1330 por Juan Ruiz, conocido como el Arcipreste de Hita, es una de las obras más originales y divertidas de toda la literatura medieval española. Se trata de una larga obra poética de más de siete mil versos que mezcla los más variados géneros: fábulas, cuentos, oraciones, sátiras, consejos morales e incluso parodias de la literatura religiosa. El propio autor afirma que su libro puede leerse de dos maneras: como advertencia contra el ''loco amor'' mundano o como invitación al ''buen amor'' divino. Sin embargo, esta declaración suena irónica, porque buena parte del libro relata con humor las aventuras amorosas, casi siempre fracasadas, de un narrador en primera persona. Entre los episodios más famosos destacan los consejos de doña Venus al protagonista, la historia de doña Endrina y don Melón, la disputa entre don Carnal y doña Cuaresma y las cantigas a las serranas, mujeres fuertes de las montañas. La mezcla de tono culto y popular, de latín y romance, de enseñanza y broma, hacen de esta obra un reflejo vivísimo de la sociedad del siglo XIV. Su métrica principal sigue siendo la cuaderna vía, aunque el autor introduce también otras formas más libres.',
'[{"pregunta":"¿Quién escribió el Libro de buen amor?","opciones":["Gonzalo de Berceo","Juan Ruiz, Arcipreste de Hita","Jorge Manrique","Don Juan Manuel"],"correcta":1},{"pregunta":"¿Aproximadamente en qué año se escribió?","opciones":["1200","1330","1450","1550"],"correcta":1},{"pregunta":"¿Qué dos tipos de amor distingue el libro?","opciones":["Amor joven y amor viejo","Loco amor y buen amor","Amor cortés y amor caballeresco","Amor pagano y amor mágico"],"correcta":1},{"pregunta":"¿Qué estrofa predomina en la obra?","opciones":["El soneto","La cuaderna vía","La décima","La silva"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{2}', 'Don Juan Manuel y El Conde Lucanor',
'Don Juan Manuel fue un noble castellano del siglo XIV, sobrino del rey Alfonso X el Sabio, que combinó su vida política con una intensa dedicación a la literatura. Su obra más famosa es ''El Conde Lucanor'', terminada hacia 1335. Se trata de una colección de cincuenta y un cuentos con una estructura muy característica: un joven noble, el conde Lucanor, consulta cada vez a su consejero Patronio sobre un problema que le preocupa; Patronio, en lugar de contestarle directamente, le explica un cuento del que el conde debe extraer la enseñanza. Al final, el propio don Juan Manuel resume la moraleja en dos versos. Los cuentos provienen de distintas tradiciones: orientales, árabes, clásicas y populares. Algunos, como el de la lechera, el del rey que se quedó desnudo o el de doña Truhana, han influido en escritores posteriores de toda Europa. La intención de don Juan Manuel era didáctica y moral, pero su gran mérito es haberlo conseguido con una prosa castellana clara, elegante y precisa. Esto lo convierte en uno de los fundadores de la prosa en español. A diferencia de su tío Alfonso X, que escribía obras enciclopédicas, don Juan Manuel buscaba una lectura accesible y entretenida, accesible a los nobles de su tiempo.',
'[{"pregunta":"¿Cuántos cuentos tiene El Conde Lucanor?","opciones":["Veinticinco","Cincuenta y uno","Cien","Doscientos"],"correcta":1},{"pregunta":"¿Quién es el consejero del conde?","opciones":["Patronio","Alfonso","Juan","Rodrigo"],"correcta":0},{"pregunta":"¿Cómo se presenta la moraleja?","opciones":["En prosa larga","En dos versos finales","En una canción","En un diálogo"],"correcta":1},{"pregunta":"¿Con quién estaba emparentado don Juan Manuel?","opciones":["Con Alfonso X el Sabio","Con el Cid","Con Berceo","Con Jorge Manrique"],"correcta":0}]'::jsonb),

('lengua', 'eso', '{2}', 'El romancero viejo',
'A finales del siglo XIV y a lo largo del siglo XV, surgió en Castilla una forma poética que iba a tener un enorme éxito popular: el romance. Se trata de un poema narrativo, de extensión variable, compuesto por versos octosílabos con rima asonante en los pares, mientras que los impares quedan libres. Los primeros romances nacieron a partir de los antiguos cantares de gesta: los juglares, al recitar fragmentos favoritos del público, los fueron separando del resto del poema hasta que adquirieron vida propia. Así se conservaron episodios del Cid, de los siete infantes de Lara o del rey don Rodrigo. Estos romances, transmitidos oralmente de generación en generación, forman lo que hoy llamamos ''romancero viejo''. A partir del siglo XVI, los poetas cultos empezaron a escribir sus propios romances imitando el estilo popular, y a esa colección se la conoce como ''romancero nuevo''. Los temas del romancero viejo son muy variados: históricos, fronterizos (batallas entre moros y cristianos), novelescos o líricos. Su lenguaje es directo, lleno de fórmulas repetidas, diálogos y efectos dramáticos. El romance siguió vivo durante siglos y aún hoy se conservan versiones en pueblos de España, de Hispanoamérica y entre los sefardíes, herederos de los judíos expulsados en 1492.',
'[{"pregunta":"¿Cuántas sílabas tienen los versos del romance?","opciones":["Seis","Ocho","Diez","Catorce"],"correcta":1},{"pregunta":"¿En qué versos aparece la rima asonante?","opciones":["En todos","En los pares","En los impares","En ninguno"],"correcta":1},{"pregunta":"¿De dónde surgieron los primeros romances?","opciones":["De los cantares de gesta","De la Biblia","De las fábulas","De las moaxajas"],"correcta":0},{"pregunta":"¿Quiénes conservan aún hoy romances antiguos fuera de España?","opciones":["Los sefardíes","Los griegos","Los egipcios","Los celtas"],"correcta":0}]'::jsonb),

('lengua', 'eso', '{2}', 'Jorge Manrique y las Coplas',
'Jorge Manrique fue un caballero y poeta castellano del siglo XV que escribió una de las obras más bellas de toda la literatura española: las ''Coplas a la muerte de su padre''. Las compuso hacia 1476, tras la muerte de don Rodrigo Manrique, su padre, famoso maestre de la Orden de Santiago. El poema está formado por cuarenta coplas de pie quebrado, una estrofa de doce versos combinando octosílabos y tetrasílabos, con rima consonante. La obra reflexiona sobre tres temas universales: el paso del tiempo, la fugacidad de la vida y la muerte como destino común de todos los hombres. Manrique utiliza imágenes célebres, como la de los ríos que van a dar en la mar, que es el morir, para expresar que todas las vidas, grandes o pequeñas, acaban igualándose al llegar al final. Sin embargo, el poema no es solo triste: Manrique distingue tres vidas, la terrenal que pasa, la de la fama que dura más y la vida eterna, verdadera meta del buen cristiano. Al final, la figura del padre aparece en paz, recibiendo la muerte con serenidad cristiana. Las coplas combinan la tradición medieval con un tono más personal y directo que anuncia ya los cambios del Renacimiento, y son consideradas una obra que cierra con dignidad la Edad Media.',
'[{"pregunta":"¿A quién dedica Manrique sus famosas coplas?","opciones":["Al rey","A su padre","A su esposa","A su hermano"],"correcta":1},{"pregunta":"¿Qué estrofa utiliza?","opciones":["El soneto","La copla de pie quebrado","El romance","La cuaderna vía"],"correcta":1},{"pregunta":"¿Cuántas vidas distingue el poema?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":1},{"pregunta":"¿Con qué compara las vidas humanas?","opciones":["Con estrellas","Con ríos","Con árboles","Con pájaros"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{2}', 'La Celestina',
'La Celestina, cuyo título original es ''Tragicomedia de Calisto y Melibea'', se publicó en 1499 y es considerada una obra decisiva de la literatura española que marca el final de la Edad Media y el comienzo del Renacimiento. Su autor, al menos del primer acto, fue probablemente un escritor anónimo, pero Fernando de Rojas, un bachiller en leyes, continuó y completó la obra. La Celestina está escrita en forma totalmente dialogada, por lo que puede considerarse teatro, aunque su gran extensión (veintiún actos en la versión definitiva) la hace inviable para ser representada entera. La historia cuenta cómo el joven Calisto se enamora perdidamente de Melibea y, para conquistarla, recurre a los servicios de Celestina, una vieja alcahueta que representa uno de los personajes más potentes de la literatura universal. Con sus trampas, Celestina consigue que los jóvenes se amen en secreto, pero la codicia de los criados provoca su muerte, a la que siguen las trágicas caídas de Calisto y Melibea. La obra retrata con un realismo asombroso los distintos estratos sociales de la época: la nobleza ociosa, los criados ambiciosos y el mundo marginal de Celestina. Su mezcla de lenguaje culto y popular, de pasión y crítica social, la convirtió en un enorme éxito desde su publicación.',
'[{"pregunta":"¿En qué año se publicó La Celestina?","opciones":["1399","1499","1599","1699"],"correcta":1},{"pregunta":"¿Quién completó la obra?","opciones":["Fernando de Rojas","Jorge Manrique","Garcilaso","Lope de Vega"],"correcta":0},{"pregunta":"¿En qué forma está escrita?","opciones":["En verso narrativo","Totalmente dialogada","En prosa descriptiva","En cartas"],"correcta":1},{"pregunta":"¿Qué personaje representa a la alcahueta?","opciones":["Melibea","Celestina","Lucrecia","Areúsa"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{2}', 'Alfonso X el Sabio y la prosa medieval',
'Alfonso X el Sabio, rey de Castilla y León entre 1252 y 1284, es una figura clave para la historia de la lengua española. Aunque no era escritor profesional, reunió en su corte de Toledo a judíos, musulmanes y cristianos para traducir, recopilar y crear obras en todos los campos del saber. Bajo su mandato, el castellano dejó de ser solo una lengua hablada y pasó a convertirse en lengua oficial de la cancillería real, sustituyendo al latín en los documentos del reino. Eso significó una normalización de la ortografía y del léxico que favoreció enormemente su expansión. Las obras impulsadas por Alfonso X abarcan casi todos los campos del conocimiento de la época. Destaca la ''General estoria'', una ambiciosa historia universal desde la creación del mundo, y la ''Estoria de España'', que narra el pasado de la Península. En el terreno legal elaboró ''Las Siete Partidas'', un código jurídico que estuvo en vigor durante siglos. También hay obras científicas, como los ''Libros del saber de astronomía'', y una preciosa colección de cantigas en gallego-portugués dedicadas a la Virgen, las ''Cantigas de Santa María''. Por todo esto, se le conoce como ''el Sabio'' y se le considera padre de la prosa castellana.',
'[{"pregunta":"¿Qué lengua sustituyó al latín en los documentos de la corte?","opciones":["El griego","El castellano","El árabe","El hebreo"],"correcta":1},{"pregunta":"¿Qué código jurídico elaboró Alfonso X?","opciones":["Las Siete Partidas","El Fuero Juzgo","Las Leyes de Toro","El Código Civil"],"correcta":0},{"pregunta":"¿En qué lengua están escritas las Cantigas de Santa María?","opciones":["Castellano","Gallego-portugués","Latín","Catalán"],"correcta":1},{"pregunta":"¿Por qué es importante Alfonso X para la lengua?","opciones":["Inventó el castellano","Lo normalizó y lo convirtió en lengua oficial","Lo prohibió","Lo tradujo al árabe"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{2}', 'La lírica tradicional castellana',
'Además de la lírica culta escrita por clérigos y nobles, en la Edad Media floreció una abundante lírica popular, transmitida oralmente de generación en generación. Los pueblos cantaban canciones cortas en sus fiestas, en sus trabajos y en sus momentos cotidianos, y muchas de ellas se conservaron gracias a que, siglos después, algunos poetas cultos las recogieron en sus cancioneros. Se trata casi siempre de composiciones breves, de dos a cuatro versos, de rima sencilla y tono emocional. Los temas más frecuentes son el amor (sobre todo visto desde la perspectiva femenina), la alborada (el amanecer que obliga a los amantes a separarse), la naturaleza, el trabajo del campo, las fiestas y las romerías. Un tipo especial son los villancicos, que en origen no eran solo navideños, sino canciones ''de villa'', es decir, populares. También destacan las serranillas, encuentros entre un caminante culto y una serrana que habita las montañas. Estos poemas son muy distintos de los refinados cancioneros cortesanos: su fuerza reside precisamente en la naturalidad. Cuando Federico García Lorca o Rafael Alberti recuperaron esta tradición en el siglo XX, lo hicieron reconociendo que en aquellas estrofas breves se escondía algo esencial de la cultura popular y de la emoción del pueblo.',
'[{"pregunta":"¿Cómo se transmitió durante siglos la lírica tradicional?","opciones":["Por escrito","Oralmente","Por teatro","Por carta"],"correcta":1},{"pregunta":"¿Qué es una alborada?","opciones":["Una canción del amanecer","Una fiesta","Un baile","Un oficio"],"correcta":0},{"pregunta":"¿Qué eran originalmente los villancicos?","opciones":["Canciones de Navidad","Canciones de villa, populares","Canciones de iglesia","Canciones militares"],"correcta":1},{"pregunta":"¿Qué poetas del siglo XX recuperaron esta tradición?","opciones":["Lorca y Alberti","Bécquer y Rosalía","Unamuno y Machado","Cela y Delibes"],"correcta":0}]'::jsonb);


