-- LENGUA 3º ESO (10 textos) — Siglo de Oro
-- =====================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('lengua', 'eso', '{3}', 'El Renacimiento: una nueva visión del mundo',
'El Renacimiento fue un movimiento cultural que nació en Italia en el siglo XIV y llegó a España en el siglo XVI. Supuso un cambio profundo en la forma de ver el mundo: frente a la mentalidad medieval, centrada en Dios y en el más allá, el Renacimiento puso en primer plano al ser humano, su razón y su capacidad para comprender la naturaleza. Esta corriente se inspiraba en la recuperación de los textos de la Antigüedad griega y latina, que los humanistas estudiaban en sus lenguas originales. En literatura, el Renacimiento trajo a España nuevas formas métricas italianas, como el endecasílabo (verso de once sílabas), el soneto y otras estrofas como la lira o la octava real. El introductor de estas novedades fue el poeta Juan Boscán, animado por el embajador veneciano Andrea Navagero en una célebre conversación que tuvieron en los jardines del Generalife granadino. Pero fue su amigo Garcilaso de la Vega, caballero y soldado, quien llevó a la perfección el estilo nuevo. Los temas preferidos fueron el amor, la naturaleza idealizada, la mitología clásica y la búsqueda de la armonía. El ideal del ''hombre de armas y letras'' resumía esta nueva figura del caballero renacentista: valiente en la guerra y culto en la paz.',
'[{"pregunta":"¿En qué siglo llegó el Renacimiento a España?","opciones":["XIV","XV","XVI","XVII"],"correcta":2},{"pregunta":"¿Qué verso italiano se introdujo en España?","opciones":["El octosílabo","El endecasílabo","El alejandrino","El heptasílabo"],"correcta":1},{"pregunta":"¿Quién introdujo las formas italianas en la poesía española?","opciones":["Garcilaso","Juan Boscán","Fray Luis","Lope de Vega"],"correcta":1},{"pregunta":"¿Qué ideal resumía al caballero renacentista?","opciones":["Hombre de armas y letras","Hombre de fe","Hombre de mar","Hombre de campo"],"correcta":0}]'::jsonb),

('lengua', 'eso', '{3}', 'Garcilaso de la Vega',
'Garcilaso de la Vega, nacido en Toledo hacia 1501, es el poeta español que mejor encarna el ideal renacentista del ''hombre de armas y letras''. Caballero al servicio del emperador Carlos V, participó en numerosas campañas militares y murió en 1536, en una de ellas, cuando apenas contaba treinta y cinco años. Su producción poética es pequeña, menos de cuarenta sonetos, tres églogas, cinco canciones y algunas epístolas, pero de una calidad extraordinaria. Escribió siguiendo el modelo italiano y mostró cómo la lengua castellana podía alcanzar la musicalidad y la elegancia del toscano de Petrarca. Su tema principal es el amor, muchas veces inspirado en Isabel Freire, una dama portuguesa que murió joven. Garcilaso canta el amor con un tono melancólico y sereno, en el que la naturaleza idealizada acompaña y refleja los sentimientos del poeta. En la Égloga I, dos pastores, Salicio y Nemoroso, lamentan sus desdichas amorosas en un paisaje bucólico. La figura del pastor es un símbolo del hombre culto en contacto con la naturaleza, alejado del ruido de la ciudad. El lenguaje de Garcilaso es claro, musical y lleno de imágenes suaves. Aunque vivió muy pocos años, su influencia en la lírica española fue enorme y sirvió de modelo a poetas de toda Europa.',
'[{"pregunta":"¿A qué servicio militar perteneció Garcilaso?","opciones":["Al de Felipe II","Al del emperador Carlos V","Al de los Reyes Católicos","Al de Felipe III"],"correcta":1},{"pregunta":"¿Qué dama inspiró buena parte de sus poemas?","opciones":["Beatriz","Laura","Isabel Freire","Dulcinea"],"correcta":2},{"pregunta":"¿Quiénes son Salicio y Nemoroso?","opciones":["Caballeros","Pastores de la Égloga I","Reyes","Soldados"],"correcta":1},{"pregunta":"¿Qué modelo poético siguió Garcilaso?","opciones":["El árabe","El italiano","El francés","El inglés"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{3}', 'Fray Luis de León y la poesía ascética',
'Dentro del Renacimiento español convivieron dos corrientes: la profana, heredera de Petrarca y centrada en el amor terreno, y la religiosa, que adaptó la perfección formal italiana para cantar la espiritualidad cristiana. Fray Luis de León fue uno de los grandes representantes de esta segunda línea. Nacido en 1527 en Belmonte (Cuenca), ingresó muy joven en la orden agustina y llegó a ser catedrático en la Universidad de Salamanca. Su vida estuvo marcada por el enfrentamiento con otros profesores que lo denunciaron a la Inquisición por haber traducido al castellano el Cantar de los Cantares, un libro bíblico. Pasó cinco años en la cárcel, y cuando por fin regresó a su cátedra pronunció aquella famosa frase: ''Decíamos ayer...'', como si nada hubiera pasado. Su poesía, aunque breve, refleja un profundo anhelo de paz, de soledad y de armonía con la naturaleza, siempre como escalón hacia Dios. En odas como ''Vida retirada'' o ''Noche serena'' defiende el ideal del ''beatus ille'' (dichoso aquel) clásico, según el cual es feliz quien huye del bullicio del mundo. Su estrofa preferida fue la lira, creada por Garcilaso, con la que consiguió una musicalidad serena y ordenada. Además de poeta, Fray Luis fue un gran prosista: escribió ''De los nombres de Cristo'' y ''La perfecta casada''.',
'[{"pregunta":"¿En qué universidad fue catedrático Fray Luis?","opciones":["Alcalá","Salamanca","Toledo","Valladolid"],"correcta":1},{"pregunta":"¿Por qué fue denunciado a la Inquisición?","opciones":["Por escribir novelas","Por traducir el Cantar de los Cantares","Por predicar en latín","Por no ir a misa"],"correcta":1},{"pregunta":"¿Qué estrofa utilizó con más frecuencia?","opciones":["La octava real","La lira","El soneto","El romance"],"correcta":1},{"pregunta":"¿Qué frase famosa pronunció al regresar a su cátedra?","opciones":["''En un lugar de La Mancha...''","''Decíamos ayer...''","''Yo soy aquel...''","''Volverán las golondrinas...''"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{3}', 'La novela picaresca y el Lazarillo',
'La novela picaresca es un género netamente español que nació en el siglo XVI con la publicación anónima de ''La vida de Lazarillo de Tormes'' en 1554. Se trata de un tipo de relato con unas características muy definidas. El protagonista es un pícaro, un muchacho de origen muy humilde que se ve obligado a servir a distintos amos para sobrevivir, y que cuenta en primera persona sus peripecias desde su nacimiento hasta su situación actual. La estructura es episódica y la obra tiene una intención crítica: a través de las experiencias del pícaro se retratan con ironía los vicios y las injusticias de la sociedad. El Lazarillo narra la infancia y juventud de un muchacho nacido a orillas del río Tormes, en Salamanca, hijo de un molinero acusado de robo. Pasa por las manos de varios amos (un ciego avaro, un clérigo mezquino, un escudero arruinado, un fraile de la Merced, un buldero...) y de cada uno aprende algo sobre el hambre, el engaño y la supervivencia. La obra fue un éxito inmediato y marcó el modelo para otras novelas picarescas posteriores, como el ''Guzmán de Alfarache'' de Mateo Alemán o ''El Buscón'' de Quevedo. Su tono realista, satírico y desengañado la convierte en una de las piezas más modernas de la literatura del Siglo de Oro.',
'[{"pregunta":"¿En qué año se publicó el Lazarillo?","opciones":["1454","1554","1654","1754"],"correcta":1},{"pregunta":"¿Quién es el autor?","opciones":["Cervantes","Quevedo","Anónimo","Lope de Vega"],"correcta":2},{"pregunta":"¿En qué persona está narrada la obra?","opciones":["Primera","Segunda","Tercera","Omnisciente"],"correcta":0},{"pregunta":"¿Qué tipo de protagonista tiene la novela picaresca?","opciones":["Un caballero","Un pícaro de origen humilde","Un pastor","Un rey"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{3}', 'Santa Teresa y San Juan de la Cruz',
'La mística es una corriente espiritual que busca la unión directa del alma con Dios a través de una experiencia inefable. En la segunda mitad del siglo XVI, España vivió una extraordinaria floración mística gracias a dos figuras fundamentales: Santa Teresa de Jesús y San Juan de la Cruz. Teresa de Cepeda y Ahumada, nacida en Ávila en 1515, fue una monja carmelita que reformó su orden fundando los llamados ''carmelitas descalzos'', de vida mucho más austera. Aunque su dedicación principal fue espiritual, escribió obras en prosa muy personales, como el ''Libro de su vida'' o ''Las Moradas'', donde describe el camino del alma hacia Dios con imágenes de castillos y jardines. Su lenguaje es sencillo, directo, con expresiones coloquiales muy vivas: Teresa escribe como habla. Su colaborador en la reforma fue San Juan de la Cruz, nacido en Fontiveros (Ávila) en 1542. Aunque dejó una obra breve, su poesía alcanza la cumbre de la lírica mística universal. Poemas como ''Noche oscura del alma'', ''Cántico espiritual'' o ''Llama de amor viva'' expresan la unión del alma con Dios usando imágenes del amor humano, inspiradas en el Cantar de los Cantares bíblico. Ambos santos fueron canonizados y Santa Teresa, en 1970, fue proclamada Doctora de la Iglesia, la primera mujer en recibir ese título.',
'[{"pregunta":"¿Dónde nació Santa Teresa?","opciones":["Ávila","Toledo","Madrid","Burgos"],"correcta":0},{"pregunta":"¿Qué orden reformó Santa Teresa?","opciones":["Los franciscanos","Los carmelitas","Los dominicos","Los jesuitas"],"correcta":1},{"pregunta":"¿Qué obra famosa es de San Juan de la Cruz?","opciones":["Las Moradas","Noche oscura del alma","El Buscón","El Quijote"],"correcta":1},{"pregunta":"¿Qué título recibió Santa Teresa en 1970?","opciones":["Patrona de España","Doctora de la Iglesia","Santa Madre","Madre Fundadora"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{3}', 'Cervantes y el Quijote, novela moderna',
'Miguel de Cervantes Saavedra nació en Alcalá de Henares en 1547 y murió en Madrid en 1616. Su vida estuvo llena de penalidades: combatió en la batalla de Lepanto, donde perdió el uso de la mano izquierda, fue cautivo en Argel durante cinco años y sufrió además grandes dificultades económicas. En 1605 publicó la primera parte de su obra maestra, ''El ingenioso hidalgo don Quijote de la Mancha'', y diez años después, en 1615, apareció la segunda parte. Con ella creó la novela moderna, un género totalmente nuevo que inspiró a escritores posteriores de todo el mundo. La obra cuenta cómo un hidalgo de un lugar de La Mancha, enloquecido por la lectura de libros de caballería, decide convertirse en caballero andante con el nombre de don Quijote y sale a recorrer España para deshacer entuertos, acompañado por su escudero Sancho Panza. Las aventuras del hidalgo y de su escudero son tan disparatadas como emocionantes: los molinos de viento que el caballero confunde con gigantes, los rebaños de ovejas que ve como ejércitos, las ventas que le parecen castillos. Pero lo que hace a esta novela inmortal no es solo el humor, sino la profundidad con que Cervantes mezcla idealismo y realismo, la risa y la melancolía. Don Quijote representa al soñador, Sancho al hombre práctico, y juntos encarnan dos lados del alma humana.',
'[{"pregunta":"¿En qué batalla perdió Cervantes el uso de la mano?","opciones":["Pavía","Lepanto","Bailén","Trafalgar"],"correcta":1},{"pregunta":"¿Cuándo apareció la primera parte del Quijote?","opciones":["1505","1605","1705","1405"],"correcta":1},{"pregunta":"¿Qué confunde don Quijote con gigantes?","opciones":["Árboles","Molinos de viento","Castillos","Rebaños"],"correcta":1},{"pregunta":"¿Qué crea Cervantes con esta obra?","opciones":["La novela picaresca","La novela moderna","El teatro barroco","El romance"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{3}', 'Lope de Vega y el teatro nacional',
'Félix Lope de Vega y Carpio, nacido en Madrid en 1562, fue el dramaturgo que creó el modelo del teatro español del Siglo de Oro. Hombre de vida intensa y apasionada, escribió una cantidad asombrosa de obras: se habla de unas mil quinientas comedias, aunque se conservan alrededor de cuatrocientas. Su gran mérito fue inventar una nueva manera de hacer teatro, adaptada al gusto del público. En 1609 expuso sus principios en el ''Arte nuevo de hacer comedias'', donde propone reglas muy distintas a las del teatro clásico. Entre ellas destaca la división en tres actos (exposición, nudo y desenlace), la mezcla de lo trágico y lo cómico, la variedad métrica adaptada a cada situación, la presencia del gracioso como contrapunto humorístico y la importancia del tema del honor, siempre relacionado con la nobleza. Las comedias de Lope solían estar escritas en verso y se representaban en los corrales, patios de vecinos adaptados como teatros. Entre sus obras más famosas destacan ''Fuenteovejuna'', donde todo un pueblo se une contra un comendador tirano, ''El perro del hortelano'', una comedia de enredos amorosos, o ''El caballero de Olmedo''. Su teatro combina la acción viva, el humor y la emoción con enseñanzas morales. Lope fue apodado ''monstruo de la naturaleza'' por la facilidad con que escribía.',
'[{"pregunta":"¿Cómo se llama el tratado donde expuso sus ideas sobre el teatro?","opciones":["Arte poética","Arte nuevo de hacer comedias","Arte de la comedia","Arte dramático"],"correcta":1},{"pregunta":"¿En cuántos actos divide Lope sus obras?","opciones":["Cinco","Cuatro","Tres","Dos"],"correcta":2},{"pregunta":"¿Qué obra suya narra la rebelión de un pueblo contra un comendador?","opciones":["El perro del hortelano","Fuenteovejuna","El caballero de Olmedo","La Dorotea"],"correcta":1},{"pregunta":"¿Cómo se conocían los teatros del Siglo de Oro?","opciones":["Anfiteatros","Corrales","Coliseos","Auditorios"],"correcta":1}]'::jsonb),

('lengua', 'eso', '{3}', 'Calderón de la Barca',
'Pedro Calderón de la Barca, nacido en Madrid en 1600, fue el gran continuador y renovador del teatro creado por Lope de Vega. Si Lope había sido sobre todo un dramaturgo popular, Calderón llevó el teatro del Siglo de Oro a una dimensión más intelectual y filosófica, con personajes que reflexionan profundamente sobre temas universales. Su estilo, claramente barroco, es complejo, lleno de metáforas, contrastes y símbolos. Su obra más famosa es ''La vida es sueño'', estrenada hacia 1635. En ella, el príncipe Segismundo, encerrado desde niño en una torre por culpa de una profecía, es liberado y puesto a prueba por su padre, el rey Basilio. La obra plantea preguntas eternas sobre el destino y la libertad humana: ¿somos libres de verdad o todo está escrito? ¿Qué es la realidad y qué es el sueño? El conocido monólogo de Segismundo, ''Sueña el rey que es rey'', se ha convertido en uno de los fragmentos más citados de la literatura española. Calderón escribió también otras grandes obras, como ''El alcalde de Zalamea'', que trata sobre la dignidad del hombre común, o ''El gran teatro del mundo'', un auto sacramental donde Dios reparte los papeles de la vida entre los hombres. Al final de su vida se ordenó sacerdote y dedicó sus últimos años a escribir autos para las fiestas del Corpus.',
'[{"pregunta":"¿Cuál es la obra más famosa de Calderón?","opciones":["Fuenteovejuna","La vida es sueño","El Buscón","La Celestina"],"correcta":1},{"pregunta":"¿Quién es el protagonista?","opciones":["Don Quijote","Segismundo","Lázaro","Calisto"],"correcta":1},{"pregunta":"¿Qué temas plantea la obra?","opciones":["El amor y la guerra","El destino y la libertad","La muerte y la fama","El honor y la venganza"],"correcta":1},{"pregunta":"¿Qué tipo de obra es ''El gran teatro del mundo''?","opciones":["Comedia","Tragedia","Auto sacramental","Entremés"],"correcta":2}]'::jsonb),

('lengua', 'eso', '{3}', 'Góngora y el culteranismo',
'Luis de Góngora y Argote, nacido en Córdoba en 1561, fue uno de los grandes poetas del Barroco español y el creador de una corriente literaria conocida como culteranismo o gongorismo. Su estilo se caracteriza por la búsqueda de la belleza formal extrema: abundancia de cultismos (palabras procedentes directamente del latín), sintaxis complicada con hipérbatos (cambios del orden natural de las palabras), muchas metáforas mitológicas y referencias a la Antigüedad clásica. Góngora escribió dos tipos muy distintos de poesía. Por un lado, una lírica popular llena de gracia, con romances y letrillas de tono amable y humorístico, fácilmente comprensibles. Por otro, unas obras mayores de enorme complicación, como ''Fábula de Polifemo y Galatea'' o ''Soledades'', poemas largos donde cada verso es un rompecabezas lleno de imágenes brillantes. Estas obras provocaron una auténtica guerra literaria. Sus admiradores, los gongoristas, veían en ellas la cumbre de la poesía. Sus detractores, encabezados por Francisco de Quevedo, se burlaban de su oscuridad. Aunque el culteranismo fue duramente criticado en los siglos siguientes, los poetas de la Generación del 27 lo revalorizaron en 1927, con motivo del tercer centenario de la muerte de Góngora, y lo convirtieron en un referente de modernidad. Hoy Góngora se considera uno de los más grandes poetas de la literatura española.',
'[{"pregunta":"¿Cómo se llama la corriente creada por Góngora?","opciones":["Conceptismo","Culteranismo","Modernismo","Romanticismo"],"correcta":1},{"pregunta":"¿Qué es un hipérbaton?","opciones":["Una rima","Cambio del orden natural de las palabras","Una metáfora","Una comparación"],"correcta":1},{"pregunta":"¿Quién fue su mayor rival literario?","opciones":["Lope de Vega","Calderón","Quevedo","Cervantes"],"correcta":2},{"pregunta":"¿Qué generación revalorizó a Góngora en 1927?","opciones":["La del 98","La del 14","La del 27","La del 50"],"correcta":2}]'::jsonb),

('lengua', 'eso', '{3}', 'Quevedo y el conceptismo',
'Francisco de Quevedo y Villegas, nacido en Madrid en 1580, es, junto con Góngora, el gran poeta del Barroco español. Personaje contradictorio y complejo, fue hombre de letras y de espada, embajador, preso político y, sobre todo, escritor de una extraordinaria versatilidad. Frente al culteranismo de Góngora, Quevedo defendió el conceptismo, una corriente que no buscaba la belleza del lenguaje sino la agudeza del pensamiento. Los conceptistas jugaban con las dobles intenciones, las paradojas, los juegos de palabras, las antítesis y los dobles sentidos, tratando de decir muchas cosas en pocos versos. Su obra es enormemente variada. Escribió sonetos amorosos de una profundidad estremecedora, como el famoso ''Amor constante más allá de la muerte'', que termina con el verso ''polvo serán, mas polvo enamorado''. También cultivó la poesía satírica, en la que se burló sin piedad de sus contemporáneos (incluido Góngora). En prosa destaca ''El Buscón'', una novela picaresca feroz, y los ''Sueños'', visiones alegóricas y satíricas de la sociedad de su tiempo. Quevedo vivió en una época de profunda crisis para España, y toda su obra refleja el pesimismo, el desengaño y la conciencia de la decadencia del imperio. Murió en 1645 tras pasar sus últimos años enfermo y retirado, pero con un lugar asegurado entre los grandes nombres de la literatura universal.',
'[{"pregunta":"¿Qué corriente defendió Quevedo?","opciones":["El culteranismo","El conceptismo","El modernismo","El surrealismo"],"correcta":1},{"pregunta":"¿Cómo termina el famoso verso de ''Amor constante''?","opciones":["''Cenizas de amor''","''Polvo serán, mas polvo enamorado''","''Eterno será mi amor''","''Yo solo te quiero a ti''"],"correcta":1},{"pregunta":"¿Qué novela picaresca escribió?","opciones":["El Lazarillo","Guzmán de Alfarache","El Buscón","Rinconete y Cortadillo"],"correcta":2},{"pregunta":"¿Qué refleja el tono general de su obra?","opciones":["Optimismo","Pesimismo y desengaño","Fe ciega","Esperanza"],"correcta":1}]'::jsonb);



