-- HISTORIA 1º ESO (10 textos) — Prehistoria y Antigüedad
-- =====================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('historia', 'eso', '{1}', 'La hominización',
'La hominización es el largo proceso de evolución biológica que condujo desde los primeros primates hasta el ser humano actual, el Homo sapiens. Duró aproximadamente seis millones de años y tuvo su origen en África. Los primeros homínidos, como los australopitecos, caminaban ya sobre dos pies (bipedismo), lo que liberó sus manos para usar objetos, aunque aún tenían un cerebro pequeño y una apariencia muy simiesca. La famosa ''Lucy'', hallada en Etiopía en 1974, es un esqueleto de Australopithecus afarensis de más de tres millones de años. Hace unos 2,5 millones de años apareció el primer miembro del género Homo: el Homo habilis, ''el hombre hábil'', así llamado porque fabricaba herramientas de piedra. Más tarde surgió el Homo erectus, que dominó el fuego, salió de África y colonizó Asia y Europa. Otros homínidos importantes fueron el Homo neanderthalensis, adaptado al frío de la Europa glacial, y finalmente el Homo sapiens, que apareció hace unos 300.000 años y que acabó siendo el único superviviente del género Homo. Durante un tiempo convivió con los neandertales, e incluso hubo cruces genéticos entre ambos. El proceso de hominización demuestra que los seres humanos somos el resultado de una evolución compleja y no un grupo aparecido de repente.',
'[{"pregunta":"¿Dónde comenzó el proceso de hominización?","opciones":["En Europa","En África","En Asia","En América"],"correcta":1},{"pregunta":"¿Qué homínido fue ''Lucy''?","opciones":["Homo habilis","Australopithecus afarensis","Homo erectus","Homo sapiens"],"correcta":1},{"pregunta":"¿Quién dominó el fuego y salió de África?","opciones":["Homo habilis","Homo erectus","Neandertal","Sapiens"],"correcta":1},{"pregunta":"¿Con qué especie humana convivió el Homo sapiens?","opciones":["Homo habilis","Homo erectus","Neandertal","Australopiteco"],"correcta":2}]'::jsonb),

('historia', 'eso', '{1}', 'El arte rupestre paleolítico',
'El arte rupestre es una de las manifestaciones culturales más asombrosas de nuestros antepasados del Paleolítico superior, hace entre 35.000 y 10.000 años. Las pinturas y los grabados se realizaban en el interior de las cuevas, a menudo en zonas oscuras y de difícil acceso, lo que indica que no eran simples decoraciones, sino que tenían un significado mágico o religioso. Los artistas paleolíticos representaban sobre todo animales: bisontes, caballos, ciervos, mamuts, rinocerontes y cabras monteses. En cambio, las figuras humanas son mucho más escasas y casi siempre esquemáticas. Se empleaban colores obtenidos de minerales (ocres, carbón, manganeso) mezclados con grasa animal, y se aplicaban con los dedos, con pinceles de musgo o soplando a través de huesos huecos. Los yacimientos más famosos del arte paleolítico europeo son la cueva de Altamira, en Cantabria (España), conocida como ''la capilla Sixtina del arte cuaternario'', y las cuevas francesas de Lascaux y Chauvet. Los expertos creen que los dibujos podrían estar relacionados con rituales de caza: al representar al animal herido, los cazadores buscarían ''atraparlo'' mágicamente antes del enfrentamiento real. También se han hallado pequeñas estatuillas femeninas, las llamadas ''venus'', vinculadas probablemente con la fertilidad. Este arte demuestra que, ya entonces, los seres humanos tenían pensamiento simbólico.',
'[{"pregunta":"¿Qué se representaba sobre todo en el arte rupestre paleolítico?","opciones":["Paisajes","Animales","Humanos","Dioses"],"correcta":1},{"pregunta":"¿Dónde se encuentra la cueva de Altamira?","opciones":["Francia","Cantabria (España)","Italia","Portugal"],"correcta":1},{"pregunta":"¿Con qué finalidad probable se hacían las pinturas?","opciones":["Decoración","Rituales mágicos de caza","Aviso de peligro","Mapas"],"correcta":1},{"pregunta":"¿Con qué se representaba la fertilidad?","opciones":["Con pinturas de soles","Con venus femeninas","Con lanzas","Con cráneos"],"correcta":1}]'::jsonb),

('historia', 'eso', '{1}', 'Los primeros poblados neolíticos',
'Con el final de la última glaciación, hace unos 10.000 años, el clima se volvió más cálido y surgió una de las transformaciones más importantes de la historia: la revolución neolítica. Los seres humanos aprendieron a cultivar la tierra y a criar animales, lo que les permitió dejar de depender exclusivamente de la caza y la recolección. Esta nueva economía productiva hizo posible el asentamiento en lugares fijos y el nacimiento de los primeros poblados estables. Çatalhöyük, en la actual Turquía, es uno de los poblados neolíticos más grandes que se conocen. Allí vivieron varios miles de personas hace unos 9.000 años en casas de adobe pegadas unas a otras, sin calles: se entraba por el tejado mediante escaleras. Sus habitantes cultivaban cereales, criaban cabras y ovejas, fabricaban cerámica y tejían. Otros poblados famosos son Jericó, en Palestina, que contaba con una muralla defensiva, y los poblados lacustres europeos, construidos sobre pilotes en lagos. El aumento de la población y la acumulación de excedentes llevaron al nacimiento de nuevas profesiones (alfareros, tejedores, herreros) y a la aparición de jerarquías sociales entre quienes tenían más y quienes tenían menos. También se desarrollaron creencias religiosas más complejas, con rituales funerarios y figuras de diosas-madre. El Neolítico puso las bases de la civilización.',
'[{"pregunta":"¿Qué aprendieron los humanos en el Neolítico?","opciones":["A cazar","A cultivar la tierra y criar animales","A hablar","A volar"],"correcta":1},{"pregunta":"¿Dónde está Çatalhöyük?","opciones":["Egipto","Turquía","Grecia","España"],"correcta":1},{"pregunta":"¿Cómo se entraba en las casas de Çatalhöyük?","opciones":["Por puertas","Por el tejado","Por ventanas","Por túneles"],"correcta":1},{"pregunta":"¿Qué caracterizaba al poblado de Jericó?","opciones":["Estaba sobre pilotes","Tenía una muralla defensiva","Era nómada","No tenía casas"],"correcta":1}]'::jsonb),

('historia', 'eso', '{1}', 'La Edad de los Metales',
'Tras el Neolítico comienza la llamada Edad de los Metales, que se divide en tres etapas en función del material que predominaba: Edad del Cobre o Calcolítico, Edad del Bronce y Edad del Hierro. El ser humano descubrió que, calentando ciertas rocas en hornos, podía obtener metales fundidos con los que fabricar herramientas y armas mucho más duraderas que las de piedra. El primer metal trabajado fue el cobre, hacia el 4000 a.C. Al mezclarlo con estaño se obtenía el bronce, una aleación más resistente que se impuso a partir del 2500 a.C. Mucho después, hacia el 1200 a.C., se aprendió a fundir y forjar el hierro, un metal más difícil de trabajar pero abundante. Con los metales aparecieron nuevos oficios: los metalúrgicos se convirtieron en especialistas muy valorados. Además, las armas metálicas favorecieron la guerra y la aparición de élites guerreras y jefes poderosos. El comercio se amplió mucho, porque el estaño, necesario para el bronce, solo se encontraba en algunas regiones concretas (Cornualles en Gran Bretaña, la Galicia actual), y había que transportarlo a largas distancias. También nacieron en esta etapa monumentos megalíticos impresionantes, como los dólmenes, los menhires y los círculos de piedras (Stonehenge es el más famoso), relacionados con cultos religiosos y con observaciones del sol.',
'[{"pregunta":"¿Qué metal se trabajó primero?","opciones":["El hierro","El cobre","El oro","El bronce"],"correcta":1},{"pregunta":"¿Con qué metal se mezcla el cobre para formar bronce?","opciones":["Estaño","Plomo","Hierro","Plata"],"correcta":0},{"pregunta":"¿Qué monumento megalítico se cita en el texto?","opciones":["Pirámides","Stonehenge","Coliseo","Partenón"],"correcta":1},{"pregunta":"¿Qué grupo social ganó poder con las armas metálicas?","opciones":["Los agricultores","Los artistas","Los jefes guerreros","Los pastores"],"correcta":2}]'::jsonb),

('historia', 'eso', '{1}', 'La escritura cuneiforme en Mesopotamia',
'La escritura es uno de los grandes inventos de la humanidad y marca el paso de la Prehistoria a la Historia. Surgió alrededor del año 3500 a.C. en Mesopotamia, una región situada entre los ríos Tigris y Éufrates (actual Iraq), por la necesidad que tenían los sumerios de llevar un control de sus cosechas, de sus rebaños y de los intercambios comerciales. Al principio se utilizaban pequeños dibujos (pictogramas) que representaban objetos concretos. Poco a poco, esos dibujos se fueron simplificando hasta convertirse en signos formados por líneas en forma de cuña, lo que dio nombre a este tipo de escritura: cuneiforme (del latín ''cuneus'', cuña). Los escribas sumerios escribían sobre tablillas de arcilla blanda con un cálamo (una cañita afilada) y después las dejaban secar al sol o las cocían para conservarlas. Gracias a este sistema se han conservado miles de documentos: recibos, leyes, contratos, poemas y cuentos. La obra literaria más famosa en cuneiforme es la Epopeya de Gilgamesh, considerada el primer gran relato literario de la historia. Aprender a escribir requería muchos años de estudio en las escuelas llamadas ''casas de las tablillas'', y los escribas eran personas muy respetadas, a menudo al servicio del templo o del palacio real. Con la escritura comenzó una nueva forma de transmitir el conocimiento.',
'[{"pregunta":"¿Dónde surgió la escritura cuneiforme?","opciones":["Egipto","Mesopotamia","China","India"],"correcta":1},{"pregunta":"¿Qué significa ''cuneiforme''?","opciones":["En forma de cuña","En forma de imagen","En forma de signo","En forma de letra"],"correcta":0},{"pregunta":"¿Sobre qué material escribían los sumerios?","opciones":["Papiro","Tablillas de arcilla","Pergamino","Papel"],"correcta":1},{"pregunta":"¿Cuál es la obra literaria cuneiforme más famosa?","opciones":["La Ilíada","La Epopeya de Gilgamesh","El Libro de los Muertos","La Odisea"],"correcta":1}]'::jsonb),

('historia', 'eso', '{1}', 'Las pirámides de Egipto',
'Las pirámides son los monumentos más famosos del Antiguo Egipto y una de las siete maravillas del mundo antiguo. Se construyeron como tumbas para los faraones, a los que se consideraba dioses vivientes. Los egipcios creían en la vida después de la muerte y pensaban que el alma del faraón necesitaba un cuerpo bien conservado y un lugar seguro para alcanzar la eternidad. Por eso lo embalsamaban, convirtiéndolo en momia, y lo enterraban con joyas, muebles, armas y alimentos dentro de una pirámide. Las primeras pirámides, como la de Zóser en Saqqara (hacia el 2650 a.C.), tenían forma escalonada. Más tarde se construyeron las grandes pirámides lisas, como las de Guiza, que incluyen la de Keops, la más alta del mundo antiguo con 146 metros de altura. Estas obras requerían el trabajo de miles de personas durante decenios. Hasta hace poco se creía que los constructores eran esclavos, pero hoy sabemos que en realidad eran trabajadores libres, bien alimentados, que trabajaban por turnos durante las crecidas del Nilo, cuando no se podía cultivar. Los bloques de piedra, algunos de varias toneladas, se arrastraban sobre trineos lubricados con agua por rampas. Junto a las pirámides se levantaban templos funerarios y, en el caso de Guiza, también la gran Esfinge, con cuerpo de león y cabeza humana.',
'[{"pregunta":"¿Para qué servían las pirámides?","opciones":["Como palacios","Como tumbas para los faraones","Como templos","Como almacenes"],"correcta":1},{"pregunta":"¿Cuál es la pirámide más alta del mundo antiguo?","opciones":["Kefrén","Zóser","Keops","Micerinos"],"correcta":2},{"pregunta":"¿Quiénes construyeron las pirámides?","opciones":["Esclavos extranjeros","Trabajadores libres","Sacerdotes","Soldados"],"correcta":1},{"pregunta":"¿Qué tiene cuerpo de león y cabeza humana?","opciones":["La momia","La Esfinge","El sarcófago","El obelisco"],"correcta":1}]'::jsonb),

('historia', 'eso', '{1}', 'Los dioses del Olimpo',
'La religión de los antiguos griegos era politeísta, es decir, adoraban a muchos dioses. Según sus mitos, los principales vivían en la cima del monte Olimpo, la montaña más alta de Grecia, y formaban una gran familia presidida por Zeus, padre de los dioses y señor del rayo. Los griegos imaginaban a sus dioses con forma humana, con sentimientos parecidos a los nuestros: podían enamorarse, enfadarse o tener envidia, pero eran inmortales y mucho más poderosos. Cada dios tenía su especialidad. Hera, esposa de Zeus, era la protectora del matrimonio. Poseidón, con su tridente, dominaba el mar. Hades reinaba en el mundo de los muertos. Atenea era la diosa de la sabiduría y la estrategia; Ares, el dios violento de la guerra; Afrodita, la diosa de la belleza y el amor. Apolo representaba las artes, la música y la adivinación, mientras que su hermana gemela Ártemis era la diosa cazadora y protectora de los animales salvajes. Hefesto era el dios herrero, que fabricaba armas y objetos prodigiosos en su fragua; Hermes, mensajero de los dioses, con sus sandalias aladas; y Dionisio, dios del vino y las fiestas. Los griegos contaban innumerables historias sobre ellos y les dedicaban templos, sacrificios y fiestas. Los romanos más tarde adoptaron esta religión cambiando solo los nombres: Zeus pasó a llamarse Júpiter, Atenea se convirtió en Minerva y así sucesivamente.',
'[{"pregunta":"¿Dónde vivían los principales dioses griegos?","opciones":["En el cielo","En el monte Olimpo","En Atenas","En el mar"],"correcta":1},{"pregunta":"¿Qué dios gobernaba el mar?","opciones":["Zeus","Hades","Poseidón","Apolo"],"correcta":2},{"pregunta":"¿Quién era la diosa de la sabiduría?","opciones":["Hera","Atenea","Afrodita","Ártemis"],"correcta":1},{"pregunta":"¿Cómo llamaron los romanos a Zeus?","opciones":["Marte","Júpiter","Mercurio","Neptuno"],"correcta":1}]'::jsonb),

('historia', 'eso', '{1}', 'La polis griega',
'La antigua Grecia no era un reino unificado como Egipto o Persia, sino un conjunto de ciudades-estado independientes llamadas polis. Cada polis tenía su propio gobierno, su ejército, sus leyes y sus costumbres, aunque todas compartían la misma lengua, la misma religión y se consideraban griegas frente a los ''bárbaros'' extranjeros. Las polis más importantes fueron Atenas y Esparta, muy distintas entre sí. Una polis griega típica se organizaba en torno a una colina fortificada llamada acrópolis (''ciudad alta''), donde se levantaban los templos más importantes, como el Partenón en Atenas. Al pie de la acrópolis se encontraba el ágora, una gran plaza pública que era el corazón de la vida ciudadana: allí se hacía política, se celebraban juicios, se comerciaba y se charlaba con los amigos. También había gimnasios para el deporte, teatros al aire libre, templos y fuentes. Los habitantes de una polis se dividían en varios grupos. Los ciudadanos eran los únicos con derechos políticos, pero solo los varones adultos nacidos en la polis podían considerarse así. Las mujeres, aunque libres, no participaban en la política y vivían sobre todo en el ámbito del hogar. Los extranjeros residentes eran llamados metecos y no tenían derechos plenos. Por debajo de todos estaban los esclavos, que realizaban los trabajos más duros y no se consideraban personas libres.',
'[{"pregunta":"¿Qué era una polis?","opciones":["Un reino","Una ciudad-estado independiente","Un ejército","Un templo"],"correcta":1},{"pregunta":"¿Qué era el ágora?","opciones":["Un templo","Una plaza pública","Una muralla","Una escuela"],"correcta":1},{"pregunta":"¿Quién podía ser ciudadano en la polis?","opciones":["Todos","Solo los varones adultos nacidos en ella","Los esclavos","Los metecos"],"correcta":1},{"pregunta":"¿Cómo se llamaba a los extranjeros residentes?","opciones":["Metecos","Ilotas","Hoplitas","Arcontes"],"correcta":0}]'::jsonb),

('historia', 'eso', '{1}', 'Las guerras médicas',
'A comienzos del siglo V a.C., el gran Imperio Persa, gobernado por Darío I y luego por su hijo Jerjes, dominaba desde Egipto hasta la India. Decidieron entonces ampliar sus territorios hacia Europa invadiendo Grecia, y así comenzaron los enfrentamientos conocidos como guerras médicas (los griegos llamaban ''medos'' a los persas). La primera guerra comenzó en el 490 a.C. Un gran ejército persa desembarcó en la llanura de Maratón, cerca de Atenas. Los atenienses, mucho menos numerosos, consiguieron una victoria sorprendente gracias a la estrategia del general Milcíades. Cuenta la leyenda que un soldado llamado Filípides recorrió corriendo los 42 kilómetros que separan Maratón de Atenas para anunciar la victoria, y al llegar murió de agotamiento. De ahí viene la famosa prueba atlética del maratón. Diez años más tarde, Jerjes lanzó una segunda invasión con un ejército aún mayor. En el paso de las Termópilas, el rey espartano Leónidas, con solo 300 soldados, resistió heroicamente a los persas hasta morir. Los invasores llegaron a saquear Atenas, pero la flota griega comandada por Temístocles los derrotó en la decisiva batalla naval de Salamina, en el 480 a.C. Un año después, la victoria terrestre de Platea acabó definitivamente con el peligro persa. Grecia, y especialmente Atenas, salió fortalecida y entró en su ''siglo de oro''.',
'[{"pregunta":"¿Quiénes luchaban en las guerras médicas?","opciones":["Griegos y romanos","Griegos y persas","Griegos y egipcios","Griegos y turcos"],"correcta":1},{"pregunta":"¿Dónde ganaron los atenienses la primera gran batalla?","opciones":["Termópilas","Maratón","Salamina","Platea"],"correcta":1},{"pregunta":"¿Qué rey murió heroicamente en las Termópilas?","opciones":["Milcíades","Leónidas","Temístocles","Pericles"],"correcta":1},{"pregunta":"¿Qué batalla naval decidió la segunda guerra?","opciones":["Salamina","Maratón","Platea","Queronea"],"correcta":0}]'::jsonb),

('historia', 'eso', '{1}', 'La vida cotidiana en Pompeya',
'Pompeya era una próspera ciudad romana situada en el sur de Italia, en las fértiles tierras cercanas al volcán Vesubio. En el año 79 d.C., una violenta erupción del Vesubio sepultó la ciudad bajo varios metros de ceniza y piedra volcánica en pocas horas. La tragedia fue enorme, pero aquella misma catástrofe conservó bajo la ceniza las calles, las casas, los muebles y hasta los cuerpos de los habitantes, congelados en el momento de su muerte. Hoy, gracias a las excavaciones arqueológicas iniciadas en el siglo XVIII, conocemos cómo era la vida cotidiana de una ciudad romana con un detalle que ningún texto escrito podría ofrecer. En Pompeya se pueden ver las calles empedradas, con aceras elevadas y pasos de peatones formados por grandes piedras que permitían cruzar sin mojarse los pies los días de lluvia. Hay tiendas de pan con los hornos intactos, lavanderías, tabernas con las jarras todavía en los estantes, baños públicos, un anfiteatro donde combatían los gladiadores y dos teatros. Las casas ricas, llamadas domus, se organizaban en torno a patios con columnas y estaban decoradas con mosaicos de suelo y pinturas murales de vivos colores. Los vecinos más pobres vivían en apartamentos en edificios de varios pisos llamados insulae. Pompeya nos muestra a los romanos como personas normales de su tiempo.',
'[{"pregunta":"¿En qué año fue sepultada Pompeya?","opciones":["49 a.C.","79 d.C.","179 d.C.","279 d.C."],"correcta":1},{"pregunta":"¿Qué volcán entró en erupción?","opciones":["Etna","Vesubio","Stromboli","Teide"],"correcta":1},{"pregunta":"¿Cómo se llamaban las casas ricas romanas?","opciones":["Insulae","Domus","Villae","Castra"],"correcta":1},{"pregunta":"¿Cómo llamaban los romanos a los edificios de apartamentos?","opciones":["Domus","Insulae","Atrium","Forum"],"correcta":1}]'::jsonb);



