-- HISTORIA 2º ESO (10 textos) — Edad Media
-- =====================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('historia', 'eso', '{2}', 'Carlomagno y el Sacro Imperio',
'Carlomagno, nacido hacia el año 742, fue el rey de los francos y el monarca más poderoso de la Europa occidental del primer milenio. Su verdadero nombre era Carlos, y recibió el apelativo de ''Magno'' (el Grande) por sus hazañas militares y políticas. Pasó gran parte de su vida en campañas militares por las que fue extendiendo su reino hasta dominar casi toda la Europa cristiana: lo que hoy son Francia, Alemania, los Países Bajos, Suiza, Austria, el norte de Italia y parte de Cataluña. En la Navidad del año 800, en Roma, el papa León III lo coronó emperador, con lo que parecía resucitar el antiguo Imperio romano de Occidente. Carlomagno estableció su corte en Aquisgrán, donde hizo construir un hermoso palacio y una capilla que todavía se conserva. Aunque él apenas sabía escribir, reunió en su corte a los hombres más cultos de su tiempo, como el sabio Alcuino de York, e impulsó la educación, la conservación de los manuscritos clásicos y la copia de libros. Este movimiento cultural se conoce como Renacimiento carolingio. También reformó la moneda, las leyes y el sistema de gobierno, dividiendo el imperio en condados vigilados por los ''missi dominici''. Tras su muerte en 814, el imperio se fragmentó y acabó dividido entre sus nietos por el Tratado de Verdún (843).',
'[{"pregunta":"¿En qué año fue coronado emperador Carlomagno?","opciones":["700","800","900","1000"],"correcta":1},{"pregunta":"¿Quién lo coronó emperador?","opciones":["León III","Gregorio I","Urbano II","Inocencio III"],"correcta":0},{"pregunta":"¿Cómo se llama el movimiento cultural impulsado por Carlomagno?","opciones":["Renacimiento carolingio","Ilustración","Barroco","Humanismo"],"correcta":0},{"pregunta":"¿Dónde estableció su corte?","opciones":["París","Roma","Aquisgrán","Colonia"],"correcta":2}]'::jsonb),

('historia', 'eso', '{2}', 'Las Cruzadas',
'Las Cruzadas fueron una serie de expediciones militares organizadas por los cristianos europeos entre los siglos XI y XIII para recuperar Tierra Santa, es decir, los lugares donde había vivido Jesucristo y que en aquel momento estaban bajo control musulmán. La primera fue convocada en 1095 por el papa Urbano II en el Concilio de Clermont, con un famoso discurso que prometía el perdón de los pecados a quienes participaran. Miles de caballeros y gentes del pueblo acudieron a la llamada y, tras una larga y dura marcha, conquistaron Jerusalén en 1099. Durante los dos siglos siguientes hubo nuevas cruzadas, a menudo desastrosas: algunas nunca llegaron a su destino, otras acabaron saqueando a los propios cristianos, como la cuarta, que tomó Constantinopla en 1204. Los reyes y caballeros más famosos que participaron fueron Ricardo Corazón de León, Luis IX de Francia o el emperador Federico Barbarroja. En el bando musulmán destacó Saladino, que reconquistó Jerusalén en 1187. Las cruzadas dejaron una huella profunda en la mentalidad medieval, crearon las órdenes militares (Templarios, Hospitalarios) y aumentaron el contacto con el mundo oriental, lo que favoreció la llegada a Europa de productos (especias, seda), técnicas (papel, vidrio) e ideas (números árabes, astronomía). Sin embargo, también provocaron mucho sufrimiento y dejaron un recuerdo amargo en el mundo islámico.',
'[{"pregunta":"¿Quién convocó la primera Cruzada?","opciones":["Gregorio VII","Urbano II","Inocencio III","León IX"],"correcta":1},{"pregunta":"¿En qué año se conquistó Jerusalén por primera vez?","opciones":["1095","1099","1187","1204"],"correcta":1},{"pregunta":"¿Qué famoso líder musulmán reconquistó Jerusalén?","opciones":["Saladino","Mahoma","Harun","Solimán"],"correcta":0},{"pregunta":"¿Qué tomó la cuarta cruzada en 1204?","opciones":["Damasco","Jerusalén","Constantinopla","El Cairo"],"correcta":2}]'::jsonb),

('historia', 'eso', '{2}', 'El castillo medieval',
'El castillo es el símbolo más reconocible de la Edad Media europea. Durante el feudalismo, los señores construían estas fortalezas para defenderse de los ataques enemigos, vigilar su territorio y mostrar su poder. Los castillos se edificaban en lugares estratégicos: en la cima de una colina, junto a un río o en un paso de montaña. Los primeros castillos, hacia el siglo X, eran de madera sobre un pequeño montículo artificial llamado mota, rodeado por una empalizada y un foso. A partir del siglo XII, al mejorar las técnicas constructivas, se empezaron a levantar en piedra, lo que los hacía más resistentes al fuego y a los asedios. Un castillo típico tenía varias partes bien diferenciadas. La muralla exterior protegía todo el recinto y estaba reforzada con torres. Una gran torre cuadrada llamada torre del homenaje servía de último refugio y de vivienda del señor. Dentro del patio de armas se encontraban los establos, las cocinas, la capilla, el pozo y los alojamientos de los soldados. Durante los asedios, los atacantes intentaban derribar las puertas con arietes, lanzar piedras con catapultas o escalar los muros con torres móviles. Los defensores respondían arrojando flechas, piedras e incluso aceite hirviendo. Con la aparición de la pólvora y los cañones, en el siglo XV, los castillos dejaron de ser invulnerables y poco a poco perdieron su importancia militar.',
'[{"pregunta":"¿Cómo se llamaba la torre principal del castillo?","opciones":["Torre del reloj","Torre del homenaje","Torre albarrana","Barbacana"],"correcta":1},{"pregunta":"¿De qué material eran los primeros castillos?","opciones":["Piedra","Madera","Ladrillo","Mármol"],"correcta":1},{"pregunta":"¿Qué máquina se usaba para lanzar piedras contra las murallas?","opciones":["Ariete","Ballesta","Catapulta","Arco"],"correcta":2},{"pregunta":"¿Qué invento acabó con la invulnerabilidad de los castillos?","opciones":["El arco","La ballesta","Los cañones y la pólvora","La lanza"],"correcta":2}]'::jsonb),

('historia', 'eso', '{2}', 'Los monasterios medievales',
'Durante la Edad Media, los monasterios fueron auténticos centros de civilización en un mundo rural, violento y en gran parte analfabeto. Los monjes y monjas, siguiendo la regla de San Benito, vivían siguiendo el lema ''ora et labora'' (reza y trabaja). Sus días se dividían entre la oración en la iglesia, el trabajo manual en el campo o los talleres y el estudio en el scriptorium. Los monasterios solían estar formados por varios edificios alrededor de un patio central llamado claustro, rodeado de galerías porticadas donde los monjes paseaban y meditaban. En la iglesia se celebraban los oficios religiosos varias veces al día, incluso de madrugada. En el refectorio comían en silencio, escuchando la lectura de un libro piadoso. Dormían en un dormitorio común y trabajaban en los campos, huertos, bodegas, molinos y talleres del monasterio, que solía ser autosuficiente. Una de las funciones más importantes de los monasterios fue la conservación y transmisión del saber. En los scriptoria, los monjes copistas copiaban a mano, durante largas horas, libros religiosos pero también obras de los autores clásicos griegos y romanos que de otra manera se habrían perdido. Gracias a su paciente trabajo, hoy conocemos muchas obras antiguas. También fundaron escuelas, hospitales y hospederías para peregrinos. Los más importantes en España fueron Silos, San Millán de la Cogolla o Santo Domingo.',
'[{"pregunta":"¿Cuál era el lema benedictino?","opciones":["Ora et labora","Veni vidi vici","Carpe diem","Pax et bonum"],"correcta":0},{"pregunta":"¿Cómo se llamaba el patio central con galerías?","opciones":["Refectorio","Claustro","Ábside","Scriptorium"],"correcta":1},{"pregunta":"¿Qué hacían los monjes en el scriptorium?","opciones":["Rezaban","Comían","Copiaban libros","Dormían"],"correcta":2},{"pregunta":"¿Qué obras conservaron los monasterios además de las religiosas?","opciones":["Obras clásicas griegas y romanas","Libros de cocina","Mapas","Cómics"],"correcta":0}]'::jsonb),

('historia', 'eso', '{2}', 'La Peste Negra',
'La Peste Negra, también llamada peste bubónica, fue la mayor catástrofe demográfica de la Edad Media europea. Llegó a Europa en 1347 procedente de Asia Central, probablemente a través de las rutas comerciales. Los genoveses que huían del asedio de la ciudad de Caffa, en Crimea, trajeron el contagio a los puertos de Italia, y desde allí la enfermedad se propagó en pocos meses por todo el continente. Se calcula que, entre 1347 y 1352, murió entre un tercio y la mitad de la población europea. La enfermedad la transmitía una bacteria (Yersinia pestis) portada por las pulgas de las ratas, aunque en aquella época nadie conocía esa causa. Los enfermos sufrían fiebre muy alta y les aparecían bubones, es decir, bultos negros en el cuello, las axilas y las ingles, de ahí su nombre. La mayoría moría en pocos días. Las ciudades, con su hacinamiento y su falta de higiene, fueron las más afectadas. La gente, asustada, buscaba explicaciones mágicas y religiosas: se organizaron procesiones, se culpó injustamente a los judíos (lo que provocó pogromos) y se multiplicaron las sectas de flagelantes que se azotaban para expiar los pecados. Las consecuencias fueron enormes: escasez de mano de obra, subida de salarios, hundimiento del sistema feudal y crisis religiosa. Europa tardó más de un siglo en recuperar la población perdida.',
'[{"pregunta":"¿En qué año llegó la Peste Negra a Europa?","opciones":["1247","1347","1447","1547"],"correcta":1},{"pregunta":"¿Qué transmitía la enfermedad?","opciones":["El aire","Las pulgas de las ratas","El agua","Los mosquitos"],"correcta":1},{"pregunta":"¿Qué proporción de europeos murió?","opciones":["Un décimo","Entre un tercio y la mitad","Un quinto","Todos"],"correcta":1},{"pregunta":"¿Qué consecuencia económica tuvo la peste?","opciones":["Bajó los salarios","Subió los salarios por falta de mano de obra","No afectó","Creó fábricas"],"correcta":1}]'::jsonb),

('historia', 'eso', '{2}', 'El Camino de Santiago',
'El Camino de Santiago es una de las grandes rutas de peregrinación cristiana, surgida en la Edad Media y todavía activa hoy en día. Su origen se remonta al siglo IX, cuando según la tradición un ermitaño llamado Pelayo descubrió en un bosque gallego la tumba del apóstol Santiago el Mayor, guiado por una luz milagrosa. Sobre aquel lugar, el rey Alfonso II de Asturias mandó construir una pequeña iglesia, y poco a poco creció en torno a ella la ciudad de Santiago de Compostela, convertida en uno de los tres grandes centros de peregrinación de la cristiandad medieval, junto con Roma y Jerusalén. A partir del siglo XI, miles de peregrinos procedentes de toda Europa se pusieron en marcha hacia Compostela. Las rutas principales atravesaban los Pirineos y seguían hacia el oeste por Pamplona, Burgos, León y Astorga hasta llegar a la catedral. El Camino favoreció el intercambio cultural, la difusión del arte románico y el nacimiento de ciudades, iglesias, hospitales y hospederías a lo largo del recorrido. Los peregrinos se distinguían por su vestimenta: la túnica, el bordón (bastón), la calabaza para el agua y la concha de vieira, que se convirtió en su símbolo. En el siglo XII se escribió el Códice Calixtino, una especie de primera guía de viaje con información práctica sobre la ruta.',
'[{"pregunta":"¿Quién encontró según la tradición la tumba del apóstol?","opciones":["Alfonso II","El ermitaño Pelayo","Santiago el Menor","Don Rodrigo"],"correcta":1},{"pregunta":"¿Qué rey mandó construir la primera iglesia?","opciones":["Alfonso II","Alfonso X","Pelayo","Fernando I"],"correcta":0},{"pregunta":"¿Qué símbolo llevaban los peregrinos?","opciones":["Una cruz","La concha de vieira","Una espada","Un libro"],"correcta":1},{"pregunta":"¿Cómo se llama la primera guía del Camino?","opciones":["Códice Calixtino","Libro de Buen Amor","Crónica General","Las Partidas"],"correcta":0}]'::jsonb),

('historia', 'eso', '{2}', 'Los gremios en las ciudades medievales',
'A partir del siglo XII, con el resurgir de las ciudades en Europa, los artesanos que ejercían un mismo oficio empezaron a organizarse en unas asociaciones llamadas gremios. Un gremio agrupaba, por ejemplo, a todos los zapateros de una ciudad, a todos los panaderos o a todos los carpinteros. Su función era múltiple: defender los intereses del oficio, controlar la calidad de los productos, fijar los precios y las condiciones de trabajo, ayudar a los miembros enfermos y organizar las fiestas del patrón. Cada gremio tenía sus propias ordenanzas, que debían ser aprobadas por las autoridades municipales. El ingreso en un gremio estaba muy regulado. Para convertirse en maestro y abrir un taller propio, había que pasar por tres etapas. Primero se era aprendiz, un muchacho joven que vivía en casa del maestro y aprendía el oficio durante varios años, sin apenas cobrar nada. Después se ascendía a oficial, con un sueldo y más responsabilidades, pero todavía bajo las órdenes de un maestro. Finalmente, si se quería ser maestro, había que superar un examen y presentar una ''obra maestra'', una pieza que demostrara la destreza adquirida. Además, solía exigirse el pago de una cuota alta, lo que hacía difícil el ascenso a los hijos de familias pobres. Los gremios controlaron muchos aspectos de la economía urbana hasta bien entrado el siglo XIX.',
'[{"pregunta":"¿Qué era un gremio?","opciones":["Un grupo de soldados","Una asociación de artesanos del mismo oficio","Un tipo de monasterio","Un consejo real"],"correcta":1},{"pregunta":"¿Cuáles son las tres etapas del aprendizaje?","opciones":["Novato, medio y avanzado","Aprendiz, oficial y maestro","Discípulo, ayudante y jefe","Principiante, experto y dueño"],"correcta":1},{"pregunta":"¿Qué hacía falta para convertirse en maestro?","opciones":["Solo pagar","Superar un examen y presentar una obra maestra","Heredar un taller","Ir a la guerra"],"correcta":1},{"pregunta":"¿Por qué era difícil llegar a maestro?","opciones":["Porque había pocos oficios","Por el examen y la cuota alta","Porque estaba prohibido","Porque faltaba tiempo"],"correcta":1}]'::jsonb),

('historia', 'eso', '{2}', 'Al-Ándalus: Córdoba y el califato',
'Al-Ándalus es el nombre que recibió el territorio de la Península Ibérica bajo dominio musulmán desde el año 711, cuando un ejército árabe y beréber cruzó el estrecho de Gibraltar, hasta 1492, cuando los Reyes Católicos conquistaron el reino de Granada. Durante casi ocho siglos, Al-Ándalus desarrolló una cultura brillantísima, síntesis de influencias árabes, cristianas, judías y visigodas. Su etapa de máximo esplendor fue el califato de Córdoba, proclamado en el año 929 por Abderramán III. Durante más de un siglo, Córdoba se convirtió en la ciudad más grande y culta de Europa occidental, con cientos de miles de habitantes, calles empedradas, iluminación nocturna, abundantes baños públicos y una extraordinaria red de bibliotecas. La biblioteca de Al-Hakam II, uno de los califas, llegó a contener, según los cronistas, más de cuatrocientos mil libros, una cifra que entonces parecía inimaginable en el resto de Europa. En Córdoba se tradujeron obras griegas, se cultivaron las ciencias, la filosofía, las matemáticas, la medicina, la astronomía y la poesía. Allí convivieron musulmanes, cristianos (mozárabes) y judíos en relativa tolerancia. El monumento más famoso de aquella etapa es la Mezquita de Córdoba, con su impresionante bosque de columnas y arcos bicromos de herradura, que todavía hoy deja asombrado a todo el que la visita.',
'[{"pregunta":"¿En qué año comenzó Al-Ándalus?","opciones":["611","711","811","911"],"correcta":1},{"pregunta":"¿Quién proclamó el califato de Córdoba?","opciones":["Abderramán I","Abderramán III","Almanzor","Tariq"],"correcta":1},{"pregunta":"¿Qué monumento famoso se construyó en Córdoba?","opciones":["La Alhambra","La Mezquita","La Giralda","El Alcázar"],"correcta":1},{"pregunta":"¿Cómo se llamaba a los cristianos de Al-Ándalus?","opciones":["Mudéjares","Mozárabes","Moriscos","Muladíes"],"correcta":1}]'::jsonb),

('historia', 'eso', '{2}', 'Los Reyes Católicos',
'Los Reyes Católicos es el nombre con el que se conoce a Isabel I de Castilla y Fernando II de Aragón, quienes se casaron en 1469 y unieron sus dos reinos en una monarquía conjunta. Su reinado, que se prolongó hasta comienzos del siglo XVI, supuso un cambio profundo en la historia de España y marca, para muchos historiadores, el paso de la Edad Media a la Edad Moderna. Durante su gobierno ocurrieron varios acontecimientos decisivos. En 1492 finalizaron la Reconquista con la toma de Granada, último reducto del reino nazarí, lo que ponía punto final a casi ocho siglos de presencia musulmana en la Península. Ese mismo año financiaron el viaje de Cristóbal Colón, que terminó con el descubrimiento de América el 12 de octubre, abriendo una nueva era en la historia mundial. También en 1492, por desgracia, firmaron el Decreto de Alhambra, que obligaba a los judíos a convertirse al cristianismo o abandonar los reinos, una decisión que tuvo consecuencias dramáticas. Los Reyes Católicos reforzaron la autoridad real frente a la nobleza, crearon la Santa Hermandad para mantener el orden, reorganizaron la hacienda pública y fundaron la Inquisición española. Su título ''Católicos'' se lo concedió el papa Alejandro VI en 1496, en reconocimiento a su defensa de la fe. Tras su muerte, la corona pasó a su nieto Carlos I, el primer Habsburgo español.',
'[{"pregunta":"¿En qué año se casaron los Reyes Católicos?","opciones":["1469","1492","1479","1500"],"correcta":0},{"pregunta":"¿Qué tres hechos ocurrieron en 1492?","opciones":["Boda, guerra y paz","Toma de Granada, descubrimiento de América y expulsión de los judíos","Nacimiento, muerte y sucesión","Reforma, contrarreforma y paz"],"correcta":1},{"pregunta":"¿Quién les dio el título de ''Católicos''?","opciones":["Alejandro VI","Urbano II","León X","Gregorio VII"],"correcta":0},{"pregunta":"¿Quién fue su sucesor?","opciones":["Felipe II","Carlos I","Juana la Loca","Felipe el Hermoso"],"correcta":1}]'::jsonb),

('historia', 'eso', '{2}', 'Gutenberg y la imprenta',
'Johannes Gutenberg, nacido hacia 1400 en la ciudad alemana de Maguncia, es considerado el inventor de la imprenta moderna, aunque algunos de sus elementos ya existían antes. Su gran aportación fue combinar varias técnicas en un único sistema eficaz: los tipos móviles de metal, la prensa derivada de las utilizadas para el vino y la tinta al óleo. Los tipos móviles eran pequeñas piezas metálicas con una letra en relieve que podían combinarse libremente para formar cualquier palabra y volverse a reutilizar después. Hacia 1455, Gutenberg imprimió su obra más famosa, la llamada ''Biblia de 42 líneas'', en latín, de la que se conservan unos pocos ejemplares, considerados hoy tesoros bibliográficos. El impacto del invento fue enorme. Hasta entonces, los libros se copiaban a mano y eran muy caros, lo que los hacía inaccesibles para la mayor parte de la población. Con la imprenta se pudieron producir libros en cantidad, con lo que su precio cayó y se multiplicó enormemente el acceso a la cultura. En solo cincuenta años, las imprentas se extendieron por toda Europa: se calcula que hacia 1500 ya se habían impreso más de veinte millones de libros. La imprenta favoreció la difusión del Renacimiento, el desarrollo de las lenguas nacionales y, muy pronto, la rápida propagación de las ideas de la Reforma protestante. Su invención es considerada uno de los hitos más decisivos de la historia.',
'[{"pregunta":"¿En qué ciudad nació Gutenberg?","opciones":["Berlín","Maguncia","Frankfurt","Colonia"],"correcta":1},{"pregunta":"¿Cuál es su obra impresa más famosa?","opciones":["La Biblia de 42 líneas","El Quijote","La Divina Comedia","La Vulgata"],"correcta":0},{"pregunta":"¿Qué aportación técnica clave combinó Gutenberg?","opciones":["La tinta china","Los tipos móviles de metal","Los cuadernos","El papel reciclado"],"correcta":1},{"pregunta":"¿Qué movimiento religioso facilitó la imprenta?","opciones":["La Reforma protestante","La Inquisición","Las Cruzadas","El Císter"],"correcta":0}]'::jsonb);



