-- HISTORIA 4º ESO (10 textos) — Contemporánea
-- =====================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('historia', 'eso', '{4}', 'La Revolución Industrial',
'La Revolución Industrial fue un proceso de transformación económica, social y tecnológica que comenzó en Inglaterra a mediados del siglo XVIII y que en unas décadas cambió por completo la forma de producir, de trabajar y de vivir. Durante miles de años, las herramientas y la energía usadas en el trabajo habían sido las mismas: músculos humanos o animales, agua y viento. A partir del siglo XVIII, una serie de inventos hicieron posible producir muchos más bienes en menos tiempo. El motor de vapor, perfeccionado por James Watt en 1769, permitió disponer por primera vez de una fuente de energía potente y móvil que no dependía del lugar donde se encontrara. Ese motor se aplicó a las máquinas de las fábricas textiles, revolucionando la producción de tejidos, y poco después al transporte. El ferrocarril, inaugurado en 1825 con la línea de Stockton a Darlington, hizo posible transportar mercancías y personas con rapidez y a bajo coste. Los barcos de vapor hicieron lo mismo con el comercio marítimo. La Revolución Industrial hizo crecer enormemente las ciudades, atrajo a millones de campesinos en busca de trabajo y creó una nueva clase social: el proletariado industrial, formado por obreros que trabajaban en las fábricas en condiciones muy duras, jornadas de hasta catorce horas y salarios bajísimos. Con el tiempo, esta situación impulsó los movimientos obreros y la lucha por los derechos laborales.',
'[{"pregunta":"¿Dónde comenzó la Revolución Industrial?","opciones":["Francia","Inglaterra","Alemania","Estados Unidos"],"correcta":1},{"pregunta":"¿Quién perfeccionó el motor de vapor?","opciones":["James Watt","Thomas Edison","George Stephenson","Henry Ford"],"correcta":0},{"pregunta":"¿En qué año se inauguró el primer ferrocarril?","opciones":["1769","1825","1850","1900"],"correcta":1},{"pregunta":"¿Qué nueva clase social surgió?","opciones":["La burguesía","El proletariado industrial","La nobleza","El clero"],"correcta":1}]'::jsonb),

('historia', 'eso', '{4}', 'Las revoluciones liberales de 1848',
'A mediados del siglo XIX, Europa vivió una gran oleada de movimientos revolucionarios conocida como ''la primavera de los pueblos''. Durante el año 1848, estallaron rebeliones casi simultáneas en Francia, los Estados italianos, los territorios alemanes, el Imperio Austrohúngaro y otros países. Las causas eran diversas, pero había algunas comunes: la insatisfacción contra los gobiernos absolutistas, el deseo de constituciones liberales, el reclamo de derechos como la libertad de prensa o el sufragio, el nacimiento de los nacionalismos y las malas condiciones de vida provocadas por la crisis económica. En Francia, las manifestaciones obligaron al rey Luis Felipe de Orleans a abdicar, y se proclamó la Segunda República, que por primera vez estableció el sufragio universal masculino. En los estados italianos y alemanes, las revueltas tuvieron un fuerte componente nacionalista: la gente pedía la unificación política de sus pueblos, divididos en docenas de pequeños estados. En el Imperio Austriaco, las minorías nacionales (húngaros, checos, croatas) exigieron mayor autonomía. Aunque la mayoría de estas revoluciones fueron aplastadas a corto plazo por las tropas imperiales o por los ejércitos conservadores, sus ideas no se perdieron. En los años siguientes, las reformas liberales, el sufragio y los movimientos nacionales acabaron triunfando poco a poco. Italia se unificó en 1861 y Alemania en 1871. El año 1848 quedó en la memoria como el momento en que toda Europa soñó con cambiar a la vez.',
'[{"pregunta":"¿Cómo se llamó el año 1848 en Europa?","opciones":["La Primavera de los Pueblos","El Año Cero","La Belle Époque","La Larga Paz"],"correcta":0},{"pregunta":"¿Qué se estableció en Francia tras 1848?","opciones":["La Primera República","La Segunda República","La Tercera República","La Restauración"],"correcta":1},{"pregunta":"¿En qué año se unificó Italia?","opciones":["1848","1861","1871","1890"],"correcta":1},{"pregunta":"¿En qué año se unificó Alemania?","opciones":["1861","1871","1890","1900"],"correcta":1}]'::jsonb),

('historia', 'eso', '{4}', 'Marie Curie y los descubrimientos científicos del 1900',
'Marie Curie, nacida Maria Skłodowska en Varsovia en 1867, fue una de las grandes figuras de la ciencia del siglo XX y la primera persona en recibir dos premios Nobel en dos disciplinas distintas. Hija de un profesor polaco, emigró a París siendo muy joven para poder estudiar, ya que en aquellos años las universidades de la Polonia rusa estaban cerradas a las mujeres. En la Sorbona se licenció en física y después en matemáticas, siempre con las mejores calificaciones, trabajando a veces en condiciones durísimas. En 1895 se casó con el físico Pierre Curie, con quien compartió no solo la vida, sino también las investigaciones. Juntos estudiaron la radiactividad, un fenómeno recién descubierto por Henri Becquerel. En 1898 anunciaron el descubrimiento de dos nuevos elementos químicos, a los que llamaron polonio (en recuerdo de la patria de Marie) y radio. Por esas investigaciones recibieron, junto con Becquerel, el Premio Nobel de Física en 1903. Tras la muerte de Pierre en un accidente en 1906, Marie continuó sola su trabajo y en 1911 recibió un segundo Premio Nobel, esta vez de Química, por aislar el radio puro. Durante la Primera Guerra Mundial, organizó unidades móviles de radiografía (las ''pequeñas Curies'') para ayudar a los cirujanos del frente. Murió en 1934 a causa de una enfermedad provocada por su exposición prolongada a la radiación, desconocida entonces.',
'[{"pregunta":"¿Cuántos premios Nobel recibió Marie Curie?","opciones":["Uno","Dos","Tres","Cuatro"],"correcta":1},{"pregunta":"¿Qué dos elementos descubrió?","opciones":["Radio y polonio","Uranio y torio","Oro y plata","Helio y neón"],"correcta":0},{"pregunta":"¿En qué año recibió su primer Nobel?","opciones":["1895","1903","1911","1920"],"correcta":1},{"pregunta":"¿Qué organizó durante la Primera Guerra Mundial?","opciones":["Hospitales de campaña","Unidades móviles de radiografía","Escuelas","Talleres"],"correcta":1}]'::jsonb),

('historia', 'eso', '{4}', 'El movimiento sufragista',
'El derecho al voto de las mujeres, que hoy nos parece evidente, no se consiguió fácilmente. Durante la mayor parte del siglo XIX y principios del XX, el sufragio estaba reservado a los hombres. A partir de mediados del siglo XIX surgió en varios países un movimiento llamado sufragismo, formado sobre todo por mujeres que reclamaban el derecho a votar y a ser elegidas en las mismas condiciones que los varones. El movimiento más famoso fue el británico, encabezado por Emmeline Pankhurst, que en 1903 fundó la Unión Social y Política de las Mujeres. Las sufragistas británicas organizaron manifestaciones, pronunciaron discursos y, cuando vieron que sus peticiones eran desatendidas, pasaron a la acción directa: rompieron escaparates, se encadenaron a las verjas del Parlamento, incendiaron buzones. Muchas fueron detenidas y sometidas a duros castigos en la cárcel, como la alimentación forzada cuando se declaraban en huelga de hambre. Una sufragista, Emily Davison, murió en 1913 tras arrojarse bajo el caballo del rey durante una carrera, un episodio que conmocionó al país. Finalmente, en 1918, el Reino Unido concedió el voto a las mujeres mayores de treinta años, y en 1928 se igualó con los hombres. En España, las mujeres pudieron votar por primera vez en 1933, gracias sobre todo a la diputada Clara Campoamor. Hoy el sufragio femenino es un derecho universalmente reconocido.',
'[{"pregunta":"¿Quién lideró el sufragismo británico?","opciones":["Clara Campoamor","Emmeline Pankhurst","Emily Davison","Simone de Beauvoir"],"correcta":1},{"pregunta":"¿En qué año votaron por primera vez las españolas?","opciones":["1918","1928","1933","1945"],"correcta":2},{"pregunta":"¿Qué diputada española defendió este derecho?","opciones":["Pasionaria","Clara Campoamor","Victoria Kent","Federica Montseny"],"correcta":1},{"pregunta":"¿Qué hicieron las sufragistas británicas cuando no las escuchaban?","opciones":["Pedir permiso","Acción directa (manifestaciones, rotura de escaparates...)","Retirarse","Emigrar"],"correcta":1}]'::jsonb),

('historia', 'eso', '{4}', 'Gandhi y la independencia de la India',
'Mohandas Karamchand Gandhi, conocido por el honorífico Mahatma (''gran alma''), fue uno de los personajes más influyentes del siglo XX. Nació en la India en 1869, estudió Derecho en Londres y vivió durante años en Sudáfrica, donde experimentó en carne propia el racismo británico y comenzó a desarrollar su método de lucha. Cuando regresó a la India en 1915, se puso al frente del movimiento por la independencia del país, que entonces llevaba casi doscientos años bajo dominio británico. Lo original de Gandhi fue su estrategia: la no violencia activa, que él llamaba ''satyagraha'' (fuerza de la verdad). Consistía en desobedecer las leyes injustas sin responder a la violencia de las autoridades, aceptar las consecuencias legales y conquistar la libertad mediante la fuerza moral, no la armada. Organizó huelgas, boicots a los productos británicos, marchas y ayunos. Uno de los actos más famosos fue la Marcha de la Sal (1930), en la que recorrió cientos de kilómetros hasta el mar para recoger sal de forma ilegal, desafiando así el monopolio británico. Durante décadas fue detenido varias veces, pero su popularidad crecía en todo el mundo. En 1947, la India consiguió finalmente la independencia, aunque con la dolorosa partición del territorio entre India y Pakistán. Solo unos meses después, en enero de 1948, Gandhi fue asesinado por un extremista hindú. Su figura inspiró a otros líderes no violentos como Martin Luther King y Nelson Mandela.',
'[{"pregunta":"¿Qué significa ''Mahatma''?","opciones":["Gran líder","Gran alma","Gran rey","Gran maestro"],"correcta":1},{"pregunta":"¿Cómo se llamaba su método de lucha?","opciones":["Satyagraha","Sharia","Bushido","Ahimsa"],"correcta":0},{"pregunta":"¿Qué marcha famosa organizó en 1930?","opciones":["Marcha de la Paz","Marcha de la Sal","Marcha de las Flores","Marcha del Hambre"],"correcta":1},{"pregunta":"¿En qué año consiguió la India la independencia?","opciones":["1930","1945","1947","1950"],"correcta":2}]'::jsonb),

('historia', 'eso', '{4}', 'El fascismo italiano',
'El fascismo nació en Italia tras la Primera Guerra Mundial como una ideología autoritaria, nacionalista y antiliberal. Su fundador, Benito Mussolini, había sido al principio socialista, pero durante la guerra cambió totalmente de ideas y defendió un nacionalismo agresivo. En 1919 creó los Fasci di Combattimento, grupos paramilitares formados por excombatientes descontentos, y dos años más tarde fundó el Partido Nacional Fascista. En un país arruinado por la guerra, con huelgas continuas, crisis económica e inestabilidad política, el discurso fascista (orden, autoridad y grandeza de Italia) fue ganando adeptos. En octubre de 1922, Mussolini organizó la célebre Marcha sobre Roma, con decenas de miles de ''camisas negras'' convergiendo hacia la capital. El rey Víctor Manuel III, asustado, le ofreció el puesto de primer ministro sin que fuera necesario disparar un tiro. En pocos años, Mussolini acabó con las libertades: prohibió los demás partidos políticos, controló los medios de comunicación, creó la policía secreta OVRA, impuso un poderoso culto a su persona (''Il Duce'', ''el Jefe'') y organizó a la juventud en grupos uniformados. Su régimen realizó algunas obras públicas vistosas y firmó los Pactos de Letrán (1929) con el Vaticano. Pero también recurrió a la violencia y emprendió guerras coloniales en Etiopía. El fascismo italiano sirvió de inspiración directa al nazismo alemán, aunque Hitler lo llevaría a extremos aún más terribles.',
'[{"pregunta":"¿Quién fundó el fascismo italiano?","opciones":["Hitler","Mussolini","Franco","Pétain"],"correcta":1},{"pregunta":"¿Cómo se conocía a los paramilitares fascistas?","opciones":["Camisas pardas","Camisas negras","Camisas azules","Camisas rojas"],"correcta":1},{"pregunta":"¿Cómo llegó Mussolini al poder?","opciones":["Por elecciones libres","Por la Marcha sobre Roma","Por un golpe militar","Por herencia"],"correcta":1},{"pregunta":"¿Con qué nombre se llamaba a Mussolini?","opciones":["El Führer","Il Duce","El Caudillo","El Líder"],"correcta":1}]'::jsonb),

('historia', 'eso', '{4}', 'El Holocausto',
'El Holocausto fue el asesinato sistemático de aproximadamente seis millones de judíos europeos por la Alemania nazi y sus colaboradores durante la Segunda Guerra Mundial. Representa uno de los episodios más oscuros y dolorosos de toda la historia de la humanidad. Desde que Hitler llegó al poder en 1933, los judíos fueron perseguidos: se les prohibió ejercer muchas profesiones, se les obligó a llevar una estrella amarilla identificativa y se los concentró en guetos en las ciudades de la Europa ocupada. A partir de 1941-1942, los nazis pusieron en marcha la llamada ''Solución Final'', un plan para exterminar a todo el pueblo judío. Construyeron campos de exterminio en Polonia, entre los que destaca Auschwitz-Birkenau, donde llegaron a morir más de un millón de personas. Allí se eliminaba a los prisioneros mediante cámaras de gas, fusilamientos, hambre, trabajos forzados y enfermedades. Junto con los judíos, fueron también víctimas del exterminio nazi los gitanos, los homosexuales, los discapacitados, los prisioneros políticos, los testigos de Jehová y los eslavos. Tras la guerra, los campos fueron liberados por los ejércitos aliados, que descubrieron escenas atroces. En 1945-1946, los Juicios de Núremberg juzgaron a los principales responsables nazis. Desde entonces, cada 27 de enero (aniversario de la liberación de Auschwitz) se celebra el Día Internacional en memoria de las víctimas, para que nunca olvidemos lo ocurrido.',
'[{"pregunta":"¿Cuántos judíos fueron asesinados?","opciones":["Unos seis millones","Unos tres millones","Unos diez millones","Unos veinte millones"],"correcta":0},{"pregunta":"¿Cómo se llamaba el campo de exterminio más conocido?","opciones":["Dachau","Auschwitz-Birkenau","Treblinka","Bergen-Belsen"],"correcta":1},{"pregunta":"¿Qué juicios se celebraron tras la guerra?","opciones":["De La Haya","De Núremberg","De Tokio","De Roma"],"correcta":1},{"pregunta":"¿Cuándo se celebra el Día Internacional?","opciones":["9 de noviembre","27 de enero","1 de septiembre","8 de mayo"],"correcta":1}]'::jsonb),

('historia', 'eso', '{4}', 'La descolonización de África',
'A lo largo del siglo XIX, las potencias europeas se repartieron la mayor parte del continente africano en forma de colonias. Tras la Segunda Guerra Mundial, esa situación se volvió insostenible. Los propios africanos, inspirados por los discursos de libertad que habían escuchado durante la guerra y por los ejemplos de la India u otras colonias asiáticas, reclamaron la independencia con fuerza creciente. A partir de 1950, una tras otra, las colonias fueron emancipándose del dominio europeo en un proceso que se llama descolonización. La fecha simbólica del inicio de la descolonización africana suele situarse en 1956-1957, cuando primero Marruecos y Túnez (de Francia) y después Ghana (del Reino Unido), al mando de Kwame Nkrumah, se independizaron pacíficamente. En 1960, considerado ''el año de África'', nada menos que diecisiete países alcanzaron la independencia. Algunos procesos fueron violentos: la guerra de Argelia contra Francia (1954-1962) causó cientos de miles de muertos, y el Congo Belga vivió una caótica transición. Las colonias portuguesas (Angola, Mozambique) no lograrían la libertad hasta 1975, tras largas guerras de liberación. En Sudáfrica, aunque independiente formalmente desde 1910, persistió el régimen racista del ''apartheid'' hasta 1994, cuando Nelson Mandela fue elegido presidente. La descolonización transformó el mapa mundial, pero dejó muchos problemas: fronteras artificiales, dictaduras, conflictos étnicos y dependencia económica.',
'[{"pregunta":"¿Qué año se conoce como ''el año de África''?","opciones":["1945","1956","1960","1975"],"correcta":2},{"pregunta":"¿Quién lideró la independencia de Ghana?","opciones":["Kwame Nkrumah","Jomo Kenyatta","Patrice Lumumba","Nelson Mandela"],"correcta":0},{"pregunta":"¿Hasta qué año duró el apartheid?","opciones":["1960","1975","1990","1994"],"correcta":3},{"pregunta":"¿Qué guerra colonial francesa fue especialmente cruenta?","opciones":["Marruecos","Argelia","Camerún","Senegal"],"correcta":1}]'::jsonb),

('historia', 'eso', '{4}', 'El 11-S y la nueva era',
'La mañana del 11 de septiembre de 2001, cuatro aviones comerciales fueron secuestrados casi a la vez por terroristas de la red yihadista Al-Qaeda, dirigida por Osama bin Laden. Dos de aquellos aviones se estrellaron contra las Torres Gemelas del World Trade Center en Nueva York, un tercero contra el edificio del Pentágono en Washington y el cuarto cayó en un campo de Pensilvania, después de que los pasajeros intentaran reducir a los secuestradores. En pocas horas, las dos enormes torres de Nueva York, de 110 plantas cada una, se derrumbaron en directo ante los ojos del mundo entero. Murieron cerca de tres mil personas. Aquel día, conocido como 11-S, cambió la historia del siglo XXI. Como respuesta, el presidente estadounidense George W. Bush declaró la llamada ''guerra contra el terror''. En pocas semanas, una coalición internacional invadió Afganistán, donde los talibanes daban refugio a Al-Qaeda. Dos años después, en 2003, Estados Unidos invadió también Irak, con el pretexto (que resultó falso) de que poseía armas de destrucción masiva. Ambas guerras duraron muchos años, con enormes costes humanos y económicos, y sus consecuencias geopolíticas todavía se sienten. En los aeropuertos del mundo entero se endurecieron los controles de seguridad. Surgieron nuevos debates sobre el equilibrio entre libertad y seguridad, y sobre el papel del islam en el mundo contemporáneo. El 11-S marcó el inicio de una nueva era.',
'[{"pregunta":"¿Qué organización estaba detrás de los atentados?","opciones":["Talibanes","Al-Qaeda","Estado Islámico","Hamás"],"correcta":1},{"pregunta":"¿Cuántas víctimas causaron los atentados?","opciones":["Unos 300","Unos 3.000","Unos 30.000","Unos 300.000"],"correcta":1},{"pregunta":"¿Qué país invadió Estados Unidos poco después?","opciones":["Irán","Irak","Afganistán","Siria"],"correcta":2},{"pregunta":"¿Quién era presidente de EE. UU. en aquel momento?","opciones":["Clinton","Bush","Obama","Trump"],"correcta":1}]'::jsonb),

('historia', 'eso', '{4}', 'La crisis climática y la sostenibilidad',
'El cambio climático es el mayor reto al que se enfrenta la humanidad en el siglo XXI. Desde mediados del siglo XIX, la quema masiva de combustibles fósiles (carbón, petróleo y gas) para producir energía, mover vehículos y hacer funcionar fábricas ha liberado enormes cantidades de dióxido de carbono a la atmósfera. Este gas, junto con otros como el metano, retiene el calor del sol en un fenómeno llamado efecto invernadero. El resultado es que la temperatura media de la Tierra está aumentando. Los efectos ya son visibles: derretimiento de glaciares y del hielo ártico, subida del nivel del mar, fenómenos meteorológicos extremos (huracanes, sequías, olas de calor), pérdida de biodiversidad y migraciones forzadas de poblaciones. Los científicos advierten desde hace décadas de la urgencia del problema. En 2015, en el llamado Acuerdo de París, casi todos los países del mundo se comprometieron a limitar el calentamiento global por debajo de los dos grados respecto a la era preindustrial. Para lograrlo, se están impulsando las energías renovables (solar, eólica, hidráulica), la movilidad eléctrica, la economía circular y nuevas formas de consumo responsable. Figuras como la joven activista sueca Greta Thunberg han puesto el tema en el centro de la opinión pública. Sin embargo, la respuesta política y económica avanza más lentamente de lo que sería deseable. Del éxito de esta transición depende el futuro del planeta.',
'[{"pregunta":"¿Qué gas es el principal responsable del efecto invernadero?","opciones":["Oxígeno","Dióxido de carbono","Nitrógeno","Hidrógeno"],"correcta":1},{"pregunta":"¿En qué año se firmó el Acuerdo de París?","opciones":["2005","2015","2020","1995"],"correcta":1},{"pregunta":"¿Qué activista sueca se cita en el texto?","opciones":["Ingrid Bergman","Greta Thunberg","Malala","Alexandria Ocasio-Cortez"],"correcta":1},{"pregunta":"¿Qué tipo de energías alternativas se impulsan?","opciones":["Fósiles","Renovables (solar, eólica...)","Nucleares exclusivamente","Carbón limpio"],"correcta":1}]'::jsonb);



