-- TUTORIA 1º ESO (10 textos) — Hábitos y emociones
-- =====================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('tutoria', 'eso', '{1}', 'Dormir bien para rendir mejor',
'El sueño es una necesidad básica de nuestro cuerpo y de nuestro cerebro, tan importante como comer o beber. Durante la adolescencia, los expertos recomiendan dormir entre ocho y diez horas cada noche, pero muchos estudios muestran que la mayoría de los jóvenes duerme bastante menos. Las consecuencias de dormir poco son más graves de lo que parece: cansancio, dificultades para concentrarse en clase, peor memoria, peor humor, bajada del rendimiento deportivo y un sistema inmunitario más débil, que hace que uno se ponga enfermo con más facilidad. Durante el sueño, el cerebro aprovecha para ordenar todo lo aprendido durante el día y guardarlo en la memoria a largo plazo. Por eso dormir bien la noche antes de un examen suele ser más eficaz que estudiar hasta las tres de la madrugada. Para tener un buen descanso, conviene seguir algunos hábitos sencillos. Primero, acostarse más o menos a la misma hora todos los días, incluso los fines de semana. Segundo, evitar las pantallas (móvil, tablet, ordenador) en la última hora antes de dormir, ya que la luz azul que emiten confunde al cerebro y le hace pensar que todavía es de día. Tercero, cenar ligero y evitar las bebidas con cafeína. Cuarto, hacer algo relajante antes de meterse en la cama, como leer o escuchar música tranquila.',
'[{"pregunta":"¿Cuántas horas recomiendan los expertos dormir a un adolescente?","opciones":["4-6","6-8","8-10","10-12"],"correcta":2},{"pregunta":"¿Qué hace el cerebro durante el sueño?","opciones":["Se apaga","Ordena lo aprendido y lo guarda en memoria","Olvida todo","Se divide"],"correcta":1},{"pregunta":"¿Qué emite la luz azul de las pantallas?","opciones":["Nada","Confunde al cerebro haciéndole pensar que es de día","Protege los ojos","Ayuda a dormir"],"correcta":1},{"pregunta":"¿Qué es mejor la noche antes de un examen?","opciones":["Estudiar hasta las 3 de la madrugada","Dormir bien","No cenar","Beber café"],"correcta":1}]'::jsonb),

('tutoria', 'eso', '{1}', 'La importancia del desayuno',
'El desayuno es, para muchos nutricionistas, la comida más importante del día, especialmente para los niños y adolescentes en edad de crecimiento. Tras una noche de ayuno de unas diez o doce horas, el cuerpo necesita recargar las reservas de energía para afrontar la actividad de la mañana: el viaje al instituto, las clases, el recreo y todo lo que ocurra hasta la hora de comer. Sin embargo, una parte importante de los adolescentes sale de casa sin desayunar o lo hace de forma muy pobre, con solo un vaso de zumo o una galleta. Las consecuencias se notan enseguida: falta de concentración, dolor de cabeza, mareos, irritabilidad y hambre antes del recreo, lo que lleva a comprar comida poco saludable en la cafetería. Un buen desayuno debe ser equilibrado y contener varios grupos de alimentos. En primer lugar, un lácteo, como un vaso de leche, un yogur o un poco de queso, que aporta calcio y proteínas. En segundo lugar, un cereal integral, como pan, tostadas o avena, que proporciona energía de liberación lenta durante varias horas. En tercer lugar, una fruta fresca (o un zumo natural), que aporta vitaminas y fibra. Hay que evitar los productos con demasiado azúcar añadido: bollería industrial, cereales azucarados y batidos. Dedicar unos diez minutos a desayunar con calma, sentado y sin prisas, es una de las mejores inversiones que se pueden hacer por la salud.',
'[{"pregunta":"¿Cuánto tiempo dura el ayuno nocturno?","opciones":["2-3 horas","5-6 horas","10-12 horas","18-20 horas"],"correcta":2},{"pregunta":"¿Qué tres grupos debe incluir un buen desayuno?","opciones":["Lácteo, cereal integral y fruta","Dulce, café y zumo","Galletas, embutido y refresco","Solo café y tostada"],"correcta":0},{"pregunta":"¿Qué problema causa no desayunar?","opciones":["Más energía","Falta de concentración y dolor de cabeza","Mejor humor","Más fuerza"],"correcta":1},{"pregunta":"¿Qué hay que evitar?","opciones":["Un lácteo","La bollería industrial","Una fruta","Un cereal integral"],"correcta":1}]'::jsonb),

('tutoria', 'eso', '{1}', 'Mi agenda, mi mejor amiga',
'La agenda es una herramienta sencilla pero muy poderosa para organizarse en la etapa de la secundaria, cuando el número de asignaturas, exámenes, trabajos y actividades extraescolares se multiplica respecto a Primaria. Aunque hoy existen aplicaciones digitales muy completas, muchos estudiantes siguen prefiriendo la agenda de papel porque escribir a mano ayuda a recordar mejor. Lo importante no es tanto el formato como el hábito de usarla diariamente. Una buena agenda escolar debe recoger varios tipos de información. En primer lugar, las fechas importantes: entregas de trabajos, exámenes, controles y lecturas obligatorias. Es muy útil señalar estos eventos con colores diferentes según la asignatura, o con pequeños iconos que llamen la atención. En segundo lugar, las tareas del día a día: los deberes que el profesor manda cada tarde y que hay que hacer antes de la siguiente clase. Conviene apuntarlos en el mismo momento en que se asignan, sin confiar en la memoria. En tercer lugar, las obligaciones extraescolares: entrenamientos, clases particulares, citas. Es importante revisar la agenda dos veces al día: al terminar las clases, para saber qué deberes tocan, y por la noche, antes de dormir, para preparar la mochila del día siguiente. Al principio cuesta crear el hábito, pero en pocas semanas la agenda se convierte en una gran aliada y ayuda a reducir el estrés y a no olvidar nada importante.',
'[{"pregunta":"¿Por qué escribir a mano ayuda?","opciones":["Porque es más bonito","Porque ayuda a recordar mejor","Porque es más rápido","Porque no gasta batería"],"correcta":1},{"pregunta":"¿Cuándo conviene apuntar los deberes?","opciones":["Al final de la semana","En el mismo momento en que los manda el profesor","Por la noche","Nunca"],"correcta":1},{"pregunta":"¿Cuántas veces al día se recomienda revisar la agenda?","opciones":["Una","Dos","Cinco","Ninguna"],"correcta":1},{"pregunta":"¿Qué recurso facilita la lectura rápida?","opciones":["Escribir en pequeño","Usar colores distintos por asignatura","No escribir nada","Usar lápiz"],"correcta":1}]'::jsonb),

('tutoria', 'eso', '{1}', 'La rueda de las emociones',
'Las emociones son reacciones naturales del cuerpo y de la mente que nos ayudan a adaptarnos a lo que ocurre a nuestro alrededor. Todas las personas sienten emociones, y todas son válidas: no hay emociones ''buenas'' o ''malas'', sino emociones agradables y desagradables. Aprender a reconocerlas es el primer paso para gestionarlas mejor. Los psicólogos suelen distinguir unas seis emociones básicas que todos los seres humanos experimentamos, independientemente de la cultura en la que hayamos crecido. Son la alegría (cuando conseguimos algo que deseábamos), la tristeza (cuando perdemos algo importante), el miedo (ante un peligro), la ira (cuando nos sentimos ofendidos o frustrados), la sorpresa (ante lo inesperado) y el asco (ante algo que nos repugna). A partir de ellas se forman combinaciones más complejas, como la vergüenza, la envidia, los celos o la culpa. Para entender lo que sentimos, un ejercicio muy útil consiste en dibujar una ''rueda de las emociones'' con los nombres de todas las que conocemos. Cuando algo nos afecta, podemos señalar la emoción correspondiente y, después, buscar palabras que la describan con más precisión. No es lo mismo estar ''enfadado'' que estar ''decepcionado'', aunque ambas estén relacionadas. Cuanto más preciso sea nuestro vocabulario emocional, mejor entenderemos lo que nos pasa y más fácil será comunicárselo a los demás.',
'[{"pregunta":"¿Qué son las emociones según el texto?","opciones":["Defectos","Reacciones naturales del cuerpo y la mente","Enfermedades","Pensamientos"],"correcta":1},{"pregunta":"¿Cuántas emociones básicas reconocen los psicólogos?","opciones":["Tres","Seis","Doce","Veinte"],"correcta":1},{"pregunta":"¿Cuál NO es una emoción básica?","opciones":["Alegría","Sorpresa","Culpa","Miedo"],"correcta":2},{"pregunta":"¿Qué propone el texto para entender lo que sentimos?","opciones":["Ignorarlo","Dibujar una rueda de las emociones","Hablar menos","Contar hasta diez"],"correcta":1}]'::jsonb),

('tutoria', 'eso', '{1}', 'Aprender a pedir ayuda',
'Pedir ayuda es una de las habilidades más importantes de la vida, pero también una de las más difíciles. A los adolescentes, que están construyendo su identidad y quieren demostrar que son autónomos, a menudo les cuesta especialmente reconocer que necesitan apoyo. Les da vergüenza admitir que no entienden algo en clase, que un compañero les está molestando o que están pasando por un momento triste en casa. Sin embargo, pedir ayuda no es ningún signo de debilidad, sino todo lo contrario: es una muestra de inteligencia y de madurez. Quienes piden ayuda a tiempo evitan que los problemas pequeños se conviertan en grandes dificultades. Hay distintos tipos de ayuda a los que un estudiante puede recurrir. Para las dudas académicas, lo primero es preguntar al profesor en clase o al final de ella; también sirve estudiar con compañeros o buscar vídeos explicativos en internet. Para los problemas personales, es fundamental hablar con alguien de confianza: los padres, un hermano mayor, un amigo, el tutor o el orientador del instituto. Para los problemas más graves, como situaciones de acoso o de violencia, existen teléfonos especializados que atienden de manera anónima y gratuita. Lo importante es no quedarse solo ni callado. Hablar de lo que nos pasa alivia la carga y, a menudo, la otra persona puede darnos un punto de vista o una solución que no habíamos considerado.',
'[{"pregunta":"¿Qué actitud se asocia erróneamente con pedir ayuda?","opciones":["Fortaleza","Debilidad","Inteligencia","Madurez"],"correcta":1},{"pregunta":"Según el texto, pedir ayuda es muestra de...","opciones":["Debilidad","Inteligencia y madurez","Pereza","Rebeldía"],"correcta":1},{"pregunta":"¿A quién acudir ante dudas académicas?","opciones":["Al médico","Al profesor","Al director","A la policía"],"correcta":1},{"pregunta":"¿Qué NO se debe hacer?","opciones":["Hablar con alguien","Quedarse solo y callado","Buscar ayuda","Preguntar"],"correcta":1}]'::jsonb),

('tutoria', 'eso', '{1}', 'Movimiento y deporte en el día a día',
'Hacer ejercicio físico con regularidad es fundamental para mantenernos sanos. La Organización Mundial de la Salud recomienda que los adolescentes realicen al menos 60 minutos de actividad física moderada o intensa cada día. Eso incluye desde actividades estructuradas, como practicar un deporte en un club, hasta cosas más sencillas: caminar al instituto, subir escaleras, bailar, jugar en el recreo o ir en bici por el barrio. Los beneficios del ejercicio van mucho más allá de la forma física. A nivel corporal, fortalece los músculos y los huesos, mejora el corazón y los pulmones, ayuda a mantener un peso saludable y refuerza las defensas. A nivel mental, libera endorfinas, unas sustancias químicas que el cerebro produce y que provocan sensación de bienestar, combaten el estrés y ayudan a sentirse más alegre. Además, moverse al aire libre aumenta los niveles de vitamina D gracias al sol. En el instituto, el ejercicio también se traduce en mejores resultados académicos. Los estudios demuestran que los alumnos más activos físicamente suelen tener mejor concentración, memoria y rendimiento escolar. Sin embargo, el estilo de vida actual, con muchas pantallas y pocas horas al aire libre, hace que muchos adolescentes no lleguen ni de lejos al mínimo recomendado. Un reto personal útil es contar los pasos diarios con el móvil y tratar de superar los 10.000 pasos cada día.',
'[{"pregunta":"¿Cuántos minutos de actividad diaria recomienda la OMS?","opciones":["30","60","90","120"],"correcta":1},{"pregunta":"¿Qué sustancias libera el ejercicio en el cerebro?","opciones":["Adrenalina","Endorfinas","Melatonina","Cortisol"],"correcta":1},{"pregunta":"¿Qué mejora el ejercicio en el estudio?","opciones":["Solo la fuerza","Concentración, memoria y rendimiento","Solo los músculos","Nada"],"correcta":1},{"pregunta":"¿Cuántos pasos diarios sugiere el texto?","opciones":["1.000","5.000","10.000","20.000"],"correcta":2}]'::jsonb),

('tutoria', 'eso', '{1}', 'El respeto en clase',
'El respeto en el aula es la base sobre la que se construye cualquier aprendizaje. Sin él, incluso el profesor mejor preparado del mundo no podría trabajar bien, y los alumnos no podrían concentrarse, preguntar o expresar sus ideas. Respetar significa reconocer el valor y la dignidad de cada persona, tratarla como nos gustaría que nos trataran a nosotros. En clase, el respeto se muestra de muchas maneras. Escuchar a quien habla, sin interrumpirlo, es la primera forma de respeto. Levantar la mano para pedir turno, en lugar de gritar o cortar al compañero, facilita que todos puedan participar. No burlarse nunca de las equivocaciones de los demás, porque todos cometemos errores y aprender significa precisamente atreverse a equivocarse. Aceptar opiniones distintas de las nuestras, sin ridiculizarlas, aunque no estemos de acuerdo. Cuidar el mobiliario del aula, los libros, los ordenadores y los materiales compartidos, porque son de todos. Hablar al profesor con educación, usando un tono correcto, incluso cuando no estamos de acuerdo con algo. El respeto se aprende con la práctica y con el ejemplo. Los grupos donde hay respeto funcionan mejor: los alumnos aprenden más, los conflictos se resuelven antes y el ambiente es agradable para todos. Cuando alguien rompe esas normas, lo correcto es avisar con calma al profesor, no ''hacerle el vacío'' ni responder con violencia.',
'[{"pregunta":"¿Qué significa respetar?","opciones":["Mandar","Reconocer el valor y dignidad de cada persona","Ignorar","Obedecer"],"correcta":1},{"pregunta":"¿Qué es la primera forma de respeto en clase?","opciones":["Escuchar sin interrumpir","Hablar alto","Sentarse delante","Copiar"],"correcta":0},{"pregunta":"¿Qué se debe hacer ante una equivocación ajena?","opciones":["Burlarse","No burlarse","Gritar","Reírse"],"correcta":1},{"pregunta":"¿Qué hacer si alguien no respeta?","opciones":["Vengarse","Avisar con calma al profesor","Ignorarlo","Darle un golpe"],"correcta":1}]'::jsonb),

('tutoria', 'eso', '{1}', 'Higiene personal en la adolescencia',
'La adolescencia trae consigo muchos cambios corporales que hacen que la higiene personal cobre más importancia que nunca. Las hormonas que se activan provocan un aumento del sudor, del olor corporal, del pelo en zonas nuevas, la aparición de granos en la piel y, en algunos casos, un exceso de grasa en el cabello. Todos estos cambios son perfectamente normales, pero requieren nuevos hábitos para mantenerse limpio, sano y cómodo. Una buena rutina de higiene incluye varios aspectos básicos. Ducharse a diario, especialmente después de practicar deporte, con agua templada y jabón. Lavarse el pelo dos o tres veces por semana (o más si es graso). Usar desodorante cada mañana, a partir del momento en que el olor corporal empieza a notarse. Lavarse las manos con frecuencia, sobre todo antes de comer y después de ir al baño. Cepillarse los dientes después de las comidas y usar hilo dental una vez al día. Cuidar la piel del rostro con un jabón suave para prevenir los granos, evitando tocárselos con las manos sucias. Cambiarse la ropa interior todos los días. La higiene personal no es solo una cuestión estética: también influye en la salud, en la autoestima y en las relaciones con los demás. Una persona aseada se siente mejor consigo misma y transmite una imagen positiva. Además, evitar la acumulación de bacterias protege contra infecciones.',
'[{"pregunta":"¿Qué cambio produce el aumento de hormonas en la adolescencia?","opciones":["Menos sudor","Aumento del sudor y del olor corporal","Pérdida de pelo","Piel seca"],"correcta":1},{"pregunta":"¿Cada cuánto hay que cepillarse los dientes?","opciones":["Una vez al día","Después de cada comida","Una vez por semana","Nunca"],"correcta":1},{"pregunta":"¿Cuándo se debe usar desodorante?","opciones":["Solo en verano","Cada mañana","Solo los fines de semana","Nunca"],"correcta":1},{"pregunta":"¿Por qué no hay que tocarse los granos?","opciones":["Porque duele","Porque las manos pueden estar sucias y empeora","Porque es ilegal","Porque es divertido"],"correcta":1}]'::jsonb),

('tutoria', 'eso', '{1}', 'Amigos y amigos de verdad',
'A lo largo de la vida nos cruzaremos con muchas personas, pero solo unas pocas se convertirán en verdaderos amigos. La amistad es una de las relaciones más bonitas y enriquecedoras que existen, y aprender a distinguir a un amigo de verdad de un simple conocido es una habilidad fundamental. Un conocido es alguien con quien intercambiamos saludos, conversaciones ocasionales o algún rato de diversión. Un amigo de verdad, en cambio, nos acompaña también en los momentos difíciles. ¿Cómo reconocer a un amigo de verdad? Un buen amigo es leal: no habla mal de nosotros a nuestras espaldas ni nos traiciona cuando hay terceras personas. Es sincero: nos dice la verdad aunque sea incómoda, porque prefiere nuestro bien a agradarnos siempre. Es respetuoso: no se burla de nuestras cosas, ni trata de cambiar quiénes somos. Es generoso con su tiempo y su atención, y se alegra sinceramente de nuestros logros, sin envidia. Sabe escuchar sin juzgar y guardar los secretos importantes. Y, sobre todo, está presente en los momentos malos, no solo en los buenos. Por otra parte, no todos los que se llaman ''amigos'' lo son de verdad. Algunos nos usan para obtener algo, otros nos presionan a hacer cosas que no queremos, otros se ríen de nosotros o nos aíslan. Si alguien nos hace sentir mal con frecuencia, probablemente no sea un buen amigo, por mucho tiempo que lleve en nuestra vida.',
'[{"pregunta":"¿Cuál NO es una característica del buen amigo según el texto?","opciones":["Leal","Sincero","Envidioso","Respetuoso"],"correcta":2},{"pregunta":"¿Cuándo se nota a un amigo de verdad?","opciones":["Solo en los momentos alegres","En los momentos difíciles","Cuando hay fiesta","Cuando se aburre"],"correcta":1},{"pregunta":"¿Qué hace un amigo con los secretos?","opciones":["Los cuenta","Los guarda","Los ignora","Los escribe"],"correcta":1},{"pregunta":"¿Qué señal indica que alguien no es un buen amigo?","opciones":["Te hace sentir bien","Te hace sentir mal con frecuencia","Te escucha","Te aprecia"],"correcta":1}]'::jsonb),

('tutoria', 'eso', '{1}', 'La técnica Pomodoro',
'La técnica Pomodoro es un método sencillo para organizar el tiempo de estudio y aumentar la concentración. Fue inventada a finales de los años ochenta por el estudiante italiano Francesco Cirillo, quien usaba un temporizador de cocina con forma de tomate (''pomodoro'' en italiano) para medir sus sesiones. El método resulta especialmente útil para quienes se distraen fácilmente o se sienten abrumados ante la cantidad de tareas pendientes. Funcionar con la técnica Pomodoro es muy fácil. Primero, eliges una tarea concreta, por ejemplo, ''leer el tema 4 de Historia'' o ''resolver diez problemas de Matemáticas''. Segundo, pones un temporizador en 25 minutos y te concentras únicamente en esa tarea, sin mirar el móvil ni hacer pausas. Si te viene una idea que no tiene que ver con lo que estás haciendo, la anotas rápidamente en un papel y sigues estudiando. Tercero, cuando suena la alarma, descansas 5 minutos: te levantas, estiras, bebes agua, miras por la ventana. Ese pequeño descanso es fundamental, porque tu cerebro necesita recuperar energía. Cuarto, repites el ciclo: cada cuatro ''pomodoros'' (25 minutos de estudio + 5 de descanso), haces un descanso más largo, de unos 15 o 20 minutos. Lo interesante de este método es que el cerebro rinde mejor cuando sabe que el esfuerzo tiene un límite claro. Después de probarlo varios días, muchos estudiantes descubren que aprovechan el tiempo el doble.',
'[{"pregunta":"¿Qué significa ''pomodoro'' en italiano?","opciones":["Tiempo","Tomate","Estudio","Descanso"],"correcta":1},{"pregunta":"¿Cuánto dura un ciclo de estudio?","opciones":["10 minutos","25 minutos","60 minutos","5 minutos"],"correcta":1},{"pregunta":"¿Cuánto dura el descanso corto?","opciones":["1 minuto","5 minutos","15 minutos","30 minutos"],"correcta":1},{"pregunta":"¿Cuántos pomodoros se hacen antes del descanso largo?","opciones":["Dos","Cuatro","Seis","Ocho"],"correcta":1}]'::jsonb);



